export interface ColorRecipe {
  name: string;
  hex: string;
  recipe: string;
}

export interface CakeDesign {
  title: string;
  visualDescription: string;
  technique: string;
  colorRecipes: ColorRecipe[];
  imageUrl?: string;
}

export interface AppState {
  isGenerating: boolean;
  result: CakeDesign | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign } from "../types";

export const generateCakeDesign = async (prompt: string, imageData?: string): Promise<CakeDesign> => {
  // We use the 3-pro-image-preview because we want both high-quality text reasoning and image output
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any[] = [{ text: prompt }];
  if (imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: imageData.split(',')[1] // remove data:image/jpeg;base64,
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        },
        responseMimeType: "application/json"
      },
    });

    let cakeData: Partial<CakeDesign> = {};
    let imageUrl: string | undefined;

    // Iterate through parts to find both JSON text and Image data
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.text) {
        try {
          // The model might return JSON wrapped in markdown or just raw JSON
          const cleanedText = part.text.replace(/```json|```/g, '').trim();
          cakeData = JSON.parse(cleanedText);
        } catch (e) {
          console.error("Failed to parse JSON response", e);
        }
      }
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    if (!cakeData.title) throw new Error("Could not generate design details.");

    return {
      title: cakeData.title || "Untitled Creation",
      visualDescription: cakeData.visualDescription || "",
      technique: cakeData.technique || "",
      colorRecipes: cakeData.colorRecipes || [],
      imageUrl: imageUrl
    };
  } catch (error: any) {
    if (error.message?.includes("Requested entity was not found")) {
      throw new Error("API_KEY_ERROR");
    }
    throw error;
  }
};

