                className="w-full py-5 bg-stone-800 text-white rounded-2xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed overflow-hidden relative group"
              >
                {state.isGenerating ? (
