                    <Loader2 className="w-5 h-5 animate-spin" />
                    Whisking colors into mist...
                  </>
                ) : (
                  <>
                    <Sparkles className="w-5 h-5 group-hover:scale-110 transition-transform" />
                    Compose Masterpiece
