export interface ColorRecipe {
  name: string;
  hex: string;
  recipe: string;
}

export interface CakeDesign {
  id?: string;
  timestamp?: number;
  title: string;
  visualDescription: string;
  technique: string;
  colorRecipes: ColorRecipe[];
  imageUrl?: string;
}

export interface AppState {
  isGenerating: boolean;
  result: CakeDesign | null;
  error: string | null;
}

import React, { useState, useEffect, useMemo } from 'react';
import { Palette, Feather, Sparkles, Image as ImageIcon, Loader2, Camera, ArrowRight, X, AlertCircle, Heart, Trash2, BookOpen } from 'lucide-react';
import { generateCakeDesign } from './services/geminiService';
import { AppState, CakeDesign } from './types';

// Extend the global Window interface using the pre-configured AIStudio type
declare global {
  interface Window {
    aistudio: AIStudio;
  }
}

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [imageFile, setImageFile] = useState<string | null>(null);
  const [state, setState] = useState<AppState>({
    isGenerating: false,
    result: null,
    error: null
  });
  const [hasKey, setHasKey] = useState<boolean | null>(null);
  const [favorites, setFavorites] = useState<CakeDesign[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);

  // Load favorites from local storage
  useEffect(() => {
    const saved = localStorage.getItem('qp_favorites');
    if (saved) {
      try {
        setFavorites(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load favorites", e);
      }
    }
  }, []);

  // Save favorites to local storage
  useEffect(() => {
    localStorage.setItem('qp_favorites', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasKey(selected);
      } catch (e) {
        setHasKey(false);
      }
    };
    checkKey();
  }, []);

  const handleKeySelect = async () => {
    try {
      await window.aistudio.openSelectKey();
      setHasKey(true);
    } catch (e) {
      console.error("Key selection failed", e);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    try {
      const result = await generateCakeDesign(prompt || "Create an impressionist cake masterpiece.", imageFile || undefined);
      // Inject ID and timestamp for favoriting
      const resultWithMeta = {
        ...result,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };
      setState({ isGenerating: false, result: resultWithMeta, error: null });
    } catch (err: any) {
      if (err.message === "API_KEY_ERROR") {
        setHasKey(false);
        setState(prev => ({ ...prev, isGenerating: false, error: "Please re-select your API key." }));
      } else {
        setState(prev => ({ ...prev, isGenerating: false, error: "The mist has settled unexpectedly. Please try again." }));
      }
    }
  };

  const toggleFavorite = (design: CakeDesign) => {
    const isFav = favorites.some(f => f.title === design.title && f.visualDescription === design.visualDescription);
    if (isFav) {
      setFavorites(favorites.filter(f => !(f.title === design.title && f.visualDescription === design.visualDescription)));
    } else {
      setFavorites([design, ...favorites]);
    }
  };

  const isFavorited = useMemo(() => {
    if (!state.result) return false;
    return favorites.some(f => f.title === state.result?.title && f.visualDescription === state.result?.visualDescription);
  }, [state.result, favorites]);

  if (hasKey === false) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#faf9f6] p-4">
        <div className="max-w-md w-full text-center space-y-8 bg-white p-10 rounded-3xl shadow-sm border border-stone-100">
          <div className="flex justify-center">
            <div className="p-4 bg-stone-50 rounded-full">
              <Palette className="w-12 h-12 text-stone-400 stroke-1" />
            </div>
          </div>
          <div className="space-y-2">
            <h1 className="text-4xl font-light tracking-tight text-stone-800">Quille en Poème</h1>
            <p className="text-stone-500 font-light">To begin the poetic journey, please select your studio key.</p>
          </div>
          <button
            onClick={handleKeySelect}
            className="w-full py-4 bg-stone-800 text-white rounded-xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-2 group"
          >
            Open Studio Key Portal
            <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
          </button>
          <p className="text-xs text-stone-400">
            Learn more about <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline hover:text-stone-600">billing and API keys</a>.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 relative">
      {/* Navigation */}
      <nav className="sticky top-0 z-50 ethereal-blur border-b border-stone-100 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-stone-800 rounded-full flex items-center justify-center">
            <span className="text-white text-xs font-serif italic">QP</span>
          </div>
          <h1 className="text-xl tracking-widest uppercase font-light text-stone-800">Quille en Poème</h1>
        </div>
        <div className="flex items-center gap-8 text-xs tracking-widest uppercase text-stone-500 font-medium">
          <button onClick={() => setShowFavorites(!showFavorites)} className="hover:text-stone-800 transition-colors flex items-center gap-2">
            <BookOpen className="w-4 h-4" />
            Collection ({favorites.length})
          </button>
        </div>
      </nav>

      {/* Favorites Sidebar/Drawer */}
      <div className={`fixed inset-y-0 right-0 w-full md:w-96 bg-white z-[60] shadow-2xl transition-transform duration-500 ease-out border-l border-stone-100 flex flex-col ${showFavorites ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-6 border-b border-stone-100 flex justify-between items-center">
          <h3 className="text-xl tracking-widest uppercase font-light text-stone-800">Ma Collection</h3>
          <button onClick={() => setShowFavorites(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors">
            <X className="w-5 h-5 text-stone-400" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {favorites.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-30 px-8">
              <Sparkles className="w-10 h-10 text-stone-400 stroke-1" />
              <p className="text-sm font-light italic">Your collection is empty. Save your favorite inspirations to see them here.</p>
            </div>
          ) : (
            favorites.map((fav, i) => (
              <div key={fav.id || i} className="group relative bg-stone-50/50 rounded-2xl overflow-hidden border border-stone-100 transition-all hover:border-stone-200">
                {fav.imageUrl && (
                  <div className="aspect-square w-full">
                    <img src={fav.imageUrl} alt={fav.title} className="w-full h-full object-cover" />
                  </div>
                )}
                <div className="p-4 space-y-3">
                  <div className="flex justify-between items-start">
                    <h4 className="text-lg serif italic text-stone-800">{fav.title}</h4>
                    <button 
                      onClick={() => toggleFavorite(fav)}
                      className="p-1.5 text-stone-300 hover:text-red-400 transition-colors"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                  <div className="flex gap-2">
                    {fav.colorRecipes.map((c, ci) => (
                      <div key={ci} className="w-4 h-4 rounded-full" style={{ backgroundColor: c.hex }} title={c.name} />
                    ))}
                  </div>
                  <button 
                    onClick={() => {
                      setState({ ...state, result: fav });
                      setShowFavorites(false);
                      window.scrollTo({ top: 0, behavior: 'smooth' });
                    }}
                    className="text-[10px] uppercase tracking-widest font-bold text-stone-400 hover:text-stone-800 flex items-center gap-1 group/btn"
                  >
                    Examiner <ArrowRight className="w-3 h-3 group-hover/btn:translate-x-1 transition-transform" />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      <main className="max-w-6xl mx-auto px-6 pt-12">
        <div className="grid lg:grid-cols-2 gap-16">

          {/* Input Section */}
          <div className="space-y-12">
            <header className="space-y-4">
              <h2 className="text-6xl font-light text-stone-800 leading-tight">Sucre en <br /><span className="italic">Poème</span></h2>
              <p className="text-stone-500 max-w-md font-light leading-relaxed">
                Transform emotions into edible impressionism. Describe a fleeting memory or upload a botanical reference to begin.
              </p>
            </header>

            <div className="space-y-8 bg-white p-8 rounded-3xl border border-stone-100 shadow-sm">
              <div className="space-y-3">
                <label className="text-xs uppercase tracking-widest font-bold text-stone-400 flex items-center gap-2">
                  <Feather className="w-3 h-3" /> Poetic Inspiration
                </label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="The first breath of spring after a long winter..."
                  className="w-full h-32 bg-stone-50 border-none rounded-2xl p-4 focus:ring-1 focus:ring-stone-200 outline-none text-stone-700 font-light resize-none placeholder:text-stone-300"
                />
              </div>

              <div className="space-y-3">
                <label className="text-xs uppercase tracking-widest font-bold text-stone-400 flex items-center gap-2">
                  <ImageIcon className="w-3 h-3" /> Visual Reference
                </label>
                <div className="relative group">
                  {imageFile ? (
                    <div className="relative aspect-video rounded-2xl overflow-hidden">
                      <img src={imageFile} alt="Reference" className="w-full h-full object-cover" />
                      <button 
                        onClick={() => setImageFile(null)}
                        className="absolute top-2 right-2 p-1 bg-black/50 text-white rounded-full hover:bg-black/70 transition-colors"
                      >
                        <X className="w-4 h-4" />
                      </button>
                    </div>
                  ) : (
                    <label className="flex flex-col items-center justify-center w-full aspect-video border-2 border-dashed border-stone-200 rounded-2xl cursor-pointer hover:bg-stone-50 hover:border-stone-300 transition-all group">
                      <div className="flex flex-col items-center justify-center pt-5 pb-6">
                        <Camera className="w-8 h-8 text-stone-300 mb-3 group-hover:text-stone-400 transition-colors" />
                        <p className="text-sm text-stone-400 font-light">Add botanical photo or texture</p>
                      </div>
                      <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                    </label>
                  )}
                </div>
              </div>

              <button
                disabled={state.isGenerating || (!prompt && !imageFile)}
                onClick={handleGenerate}
                className="w-full py-5 bg-stone-800 text-white rounded-2xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed overflow-hidden relative group"
              >
                {state.isGenerating ? (
                  <>
                    <Loader2 className="w-5 h-5 animate-spin" />
                    Whisking colors into mist...
                  </>
                ) : (
                  <>
                    <Sparkles className="w-5 h-5 group-hover:scale-110 transition-transform" />
                    Compose Masterpiece
                  </>
                )}
              </button>

              {state.error && (
                <div className="flex items-center gap-2 text-red-500 text-sm bg-red-50 p-4 rounded-xl">
                  <AlertCircle className="w-4 h-4" />
                  {state.error}
                </div>
              )}
            </div>
          </div>

          {/* Result Section */}
          <div className="lg:sticky lg:top-28 h-fit">
            {state.isGenerating ? (
              <div className="aspect-[4/5] bg-stone-100 rounded-[2rem] flex flex-col items-center justify-center p-12 text-center space-y-6 animate-pulse border border-stone-200">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center">
                  <Loader2 className="w-8 h-8 text-stone-300 animate-spin" />
                </div>
                <div className="space-y-2">
                  <p className="text-xl serif italic text-stone-400">Capturing the soul of the flower...</p>
                  <p className="text-stone-300 text-xs uppercase tracking-widest font-bold">Painting with spatula strokes</p>
                </div>
              </div>
            ) : state.result ? (
              <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
                {state.result.imageUrl && (
                  <div className="aspect-[4/5] rounded-[2rem] overflow-hidden shadow-2xl border border-stone-100 bg-white relative group">
                    <img 
                      src={state.result.imageUrl} 
                      alt={state.result.title} 
