import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign } from "../types";

export const generateCakeDesign = async (prompt: string, imageData?: string): Promise<CakeDesign> => {
  // Always create a new instance right before the call to ensure it uses the latest process.env.API_KEY.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any[] = [{ text: prompt }];
  if (imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: imageData.split(',')[1] // extract base64 data
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        },
        // responseMimeType: "application/json" is not used here to ensure we get both text and image parts
      },
    });

    let cakeData: Partial<CakeDesign> = {};
    let imageUrl: string | undefined;

    // Use .text property to get the combined text/JSON part
    const fullText = response.text || "";
    try {
      const cleanedText = fullText.replace(/```json|```/g, '').trim();
      cakeData = JSON.parse(cleanedText);
    } catch (e) {
      console.error("Failed to parse JSON response text", e, fullText);
    }

    // Iterate through parts to find the image specifically
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    if (!cakeData.title) {
      throw new Error("The creative vision was clouded. Please try again.");
    }

    return {
      title: cakeData.title || "Untitled Creation",
      visualDescription: cakeData.visualDescription || "",
      technique: cakeData.technique || "",
      colorRecipes: cakeData.colorRecipes || [],
      imageUrl: imageUrl
    };
  } catch (error: any) {
    if (error.message?.includes("Requested entity was not found")) {
      throw new Error("API_KEY_ERROR");
    }
    throw error;
  }
};

