import { generateCakeDesign } from './services/geminiService';
import { AppState, CakeDesign } from './types';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [imageFile, setImageFile] = useState<string | null>(null);
  const [state, setState] = useState<AppState>({
    isGenerating: false,
    result: null,
    error: null
  });
  const [hasKey, setHasKey] = useState<boolean | null>(null);
  const [favorites, setFavorites] = useState<CakeDesign[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);

  // Load favorites from local storage
  useEffect(() => {
    const saved = localStorage.getItem('qp_favorites');
    if (saved) {
      try {
        setFavorites(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load favorites", e);
      }
    }
  }, []);

  // Save favorites to local storage
  useEffect(() => {
    localStorage.setItem('qp_favorites', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const studio = (window as any).aistudio;
        if (studio && typeof studio.hasSelectedApiKey === 'function') {
          const selected = await studio.hasSelectedApiKey();
          setHasKey(selected);
        } else {
          setHasKey(true); // Fallback
        }
      } catch (e) {
        setHasKey(false);
      }
    };
    checkKey();
  }, []);

  const handleKeySelect = async () => {
    try {
      const studio = (window as any).aistudio;
      if (studio && typeof studio.openSelectKey === 'function') {
        await studio.openSelectKey();
        setHasKey(true);
      }
    } catch (e) {
      console.error("Key selection failed", e);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    try {
      const result = await generateCakeDesign(prompt || "Create an impressionist cake masterpiece.", imageFile || undefined);
      const resultWithMeta = {
        ...result,
        id: Math.random().toString(36).substring(2, 9),
        timestamp: Date.now()
      };
      setState({ isGenerating: false, result: resultWithMeta, error: null });
    } catch (err: any) {
      if (err.message === "API_KEY_ERROR") {
        setHasKey(false);
        setState(prev => ({ ...prev, isGenerating: false, error: "Authentication required. Please select a Studio key." }));
