          >
            Select Studio Key
            <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 relative">
      <nav className="sticky top-0 z-50 ethereal-blur border-b border-stone-100 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-stone-800 rounded-full flex items-center justify-center">
            <span className="text-white text-xs font-serif italic">QP</span>
          </div>
          <h1 className="text-xl tracking-widest uppercase font-light text-stone-800">Quille en Poème</h1>
        </div>
        <div className="flex items-center gap-8 text-xs tracking-widest uppercase text-stone-500 font-medium">
          <button onClick={() => setShowFavorites(!showFavorites)} className="hover:text-stone-800 transition-colors flex items-center gap-2">
            <BookOpen className="w-4 h-4" />
            Collection ({favorites.length})
          </button>
        </div>
      </nav>

      <div className={`fixed inset-y-0 right-0 w-full md:w-96 bg-white z-[60] shadow-2xl transition-transform duration-500 ease-out border-l border-stone-100 flex flex-col ${showFavorites ? 'translate-x-0' : 'translate-x-full'}`}>
