        setHasKey(false);
      }
    };
    checkKey();
  }, []);

  const handleKeySelect = async () => {
    try {
      const studio = (window as any).aistudio;
      if (studio && typeof studio.openSelectKey === 'function') {
        await studio.openSelectKey();
        setHasKey(true);
      }
    } catch (e) {
      console.error("Key selection failed", e);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    try {
      const result = await generateCakeDesign(prompt || "Create an impressionist cake masterpiece.", imageFile || undefined);
      const resultWithMeta = {
        ...result,
        id: Math.random().toString(36).substring(2, 9),
        timestamp: Date.now()
      };
      setState({ isGenerating: false, result: resultWithMeta, error: null });
    } catch (err: any) {
      if (err.message === "API_KEY_ERROR") {
        setHasKey(false);
        setState(prev => ({ ...prev, isGenerating: false, error: "Authentication required. Please select a Studio key." }));
      } else {
        setState(prev => ({ ...prev, isGenerating: false, error: "The mist has settled unexpectedly. Please try again." }));
      }
    }
  };

  const toggleFavorite = (design: CakeDesign) => {
    const isFav = favorites.some(f => f.title === design.title && f.visualDescription === design.visualDescription);
    if (isFav) {
      setFavorites(favorites.filter(f => !(f.title === design.title && f.visualDescription === design.visualDescription)));
    } else {
      setFavorites([design, ...favorites]);
    }
  };

  const isFavorited = useMemo(() => {
    if (!state.result) return false;
    return favorites.some(f => f.title === state.result?.title && f.visualDescription === state.result?.visualDescription);
  }, [state.result, favorites]);

  const safeStr = (val: any) => (typeof val === 'string' ? val : (val ? JSON.stringify(val) : ''));

  if (hasKey === false) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#faf9f6] p-4">
        <div className="max-w-md w-full text-center space-y-8 bg-white p-10 rounded-3xl shadow-sm border border-stone-100">
          <div className="flex justify-center">
            <div className="p-4 bg-stone-50 rounded-full">
              <Palette className="w-12 h-12 text-stone-400 stroke-1" />
            </div>
          </div>
          <div className="space-y-2">
            <h1 className="text-4xl font-light tracking-tight text-stone-800">Quille en Poème</h1>
            <p className="text-stone-500 font-light">To unlock the studio, please select your payment-ready API key.</p>
          </div>
          <button
            onClick={handleKeySelect}
            className="w-full py-4 bg-stone-800 text-white rounded-xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-2 group"
          >
            Select Studio Key
            <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 relative bg-[#faf9f6]">
      <nav className="sticky top-0 z-50 ethereal-blur border-b border-stone-100 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-stone-800 rounded-full flex items-center justify-center">
            <span className="text-white text-xs font-serif italic">QP</span>
          </div>
          <h1 className="text-xl tracking-widest uppercase font-light text-stone-800">Quille en Poème</h1>
        </div>
        <div className="flex items-center gap-8 text-xs tracking-widest uppercase text-stone-500 font-medium">
          <button onClick={() => setShowFavorites(!showFavorites)} className="hover:text-stone-800 transition-colors flex items-center gap-2">
            <BookOpen className="w-4 h-4" />
            Collection ({favorites.length})
          </button>
        </div>
      </nav>

      {/* Logic Reference Panel */}
      <div className={`fixed inset-y-0 left-0 w-full md:w-80 bg-white z-[60] shadow-2xl transition-transform duration-500 ease-out border-r border-stone-100 flex flex-col ${showLogic ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 border-b border-stone-100 flex justify-between items-center">
          <h3 className="text-sm tracking-widest uppercase font-bold text-stone-800">Mixing Philosophy</h3>
          <button onClick={() => setShowLogic(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors"><X className="w-4 h-4" /></button>
        </div>
        <div className="p-6 space-y-8 overflow-y-auto">
          <div className="space-y-4">
            <h4 className="text-xs uppercase tracking-widest font-bold text-stone-400">The Peotraco Set</h4>
            <div className="flex flex-wrap gap-2">
              {["Orange", "Black", "Green", "White", "Red", "Brown", "Yellow", "Blue"].map(c => (
                <span key={c} className="px-2 py-1 bg-stone-50 text-[10px] rounded-md border border-stone-100 text-stone-600 font-medium">{c}</span>
              ))}
            </div>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Dusty / Muted Tones</h4>
              <p className="text-xs text-stone-500 font-light leading-relaxed">Base Color + touch of Brown + plenty of White.</p>
            </div>
            <div className="space-y-2">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Vintage Greens</h4>
              <p className="text-xs text-stone-500 font-light leading-relaxed">Green + touch of Orange (to kill neon) + White.</p>
            </div>
            <div className="space-y-2">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Twilight Purples</h4>
              <p className="text-xs text-stone-500 font-light leading-relaxed">Blue + Red + touch of Black + White.</p>
            </div>
            <div className="space-y-2">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Champagne / Cream</h4>
              <p className="text-xs text-stone-500 font-light leading-relaxed">White + tiny dot of Yellow + tiny dot of Brown.</p>
            </div>
          </div>
        </div>
      </div>

      <div className={`fixed inset-y-0 right-0 w-full md:w-96 bg-white z-[60] shadow-2xl transition-transform duration-500 ease-out border-l border-stone-100 flex flex-col ${showFavorites ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-6 border-b border-stone-100 flex justify-between items-center">
          <h3 className="text-xl tracking-widest uppercase font-light text-stone-800">Ma Collection</h3>
          <button onClick={() => setShowFavorites(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors"><X className="w-5 h-5" /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {favorites.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-30 px-8">
              <Sparkles className="w-10 h-10 text-stone-400 stroke-1" />
              <p className="text-sm font-light italic">Your collection is empty.</p>
            </div>
          ) : (
            favorites.map((fav, i) => (
              <div key={fav.id || i} className="group relative bg-stone-50/50 rounded-2xl overflow-hidden border border-stone-100 transition-all hover:border-stone-200 p-4">
                <div className="flex justify-between items-start mb-2">
                  <h4 className="text-lg serif italic text-stone-800">{safeStr(fav.title)}</h4>
                  <button onClick={() => toggleFavorite(fav)} className="text-stone-300 hover:text-red-400"><Trash2 className="w-4 h-4" /></button>
                </div>
                {fav.imageUrl && <img src={fav.imageUrl} alt="" className="w-full aspect-square object-cover rounded-lg mb-3" />}
                <button 
                  onClick={() => { setState({ ...state, result: fav }); setShowFavorites(false); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
                  className="text-[10px] uppercase font-bold text-stone-400 hover:text-stone-800"
                >
                  Examiner
                </button>
              </div>
            ))
          )}
        </div>
      </div>

      <main className="max-w-6xl mx-auto px-6 pt-12">
        <div className="grid lg:grid-cols-2 gap-16">
          <div className="space-y-12">
            <header className="space-y-4">
              <h2 className="text-6xl font-light text-stone-800 leading-tight">Sucre en <br /><span className="italic">Poème</span></h2>
              <p className="text-stone-500 max-w-md font-light leading-relaxed">
                Transform fleeting memories into edible art. Our creative director uses strictly spatula work to interpret your botanical inspirations.
              </p>
              <button 
                onClick={() => setShowLogic(true)}
                className="text-[10px] uppercase tracking-widest font-bold text-stone-400 hover:text-stone-800 flex items-center gap-2 pt-2 transition-colors"
              >
                <Info className="w-3 h-3" /> View Color Logic
              </button>
            </header>

            <div className="space-y-8 bg-white p-8 rounded-3xl border border-stone-100 shadow-sm">
              <div className="space-y-3">
                <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-stone-400 flex items-center gap-2"><Feather className="w-3 h-3" /> The Poem</label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="The first breath of spring after a long winter..."
                  className="w-full h-32 bg-stone-50 border-none rounded-2xl p-4 focus:ring-1 focus:ring-stone-200 outline-none text-stone-700 font-light resize-none placeholder:text-stone-300"
                />
              </div>

              <div className="space-y-3">
                <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-stone-400 flex items-center gap-2"><ImageIcon className="w-3 h-3" /> Botanical Soul</label>
                <div className="relative group">
                  {imageFile ? (
                    <div className="relative aspect-video rounded-2xl overflow-hidden shadow-inner">
                      <img src={imageFile} alt="Reference" className="w-full h-full object-cover" />
                      <button onClick={() => setImageFile(null)} className="absolute top-3 right-3 p-1.5 bg-black/40 text-white rounded-full backdrop-blur-md hover:bg-black/60 transition-colors"><X className="w-4 h-4" /></button>
                    </div>
                  ) : (
                    <label className="flex flex-col items-center justify-center w-full aspect-video border-2 border-dashed border-stone-200 rounded-2xl cursor-pointer hover:bg-stone-50 hover:border-stone-300 transition-all">
                      <Camera className="w-8 h-8 text-stone-300 mb-3" />
                      <p className="text-sm text-stone-400 font-light">Upload photo or texture</p>
                      <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                    </label>
                  )}
                </div>
              </div>

              <button
                disabled={state.isGenerating || (!prompt && !imageFile)}
                onClick={handleGenerate}
                className="w-full py-5 bg-stone-800 text-white rounded-2xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-3 disabled:opacity-50"
              >
                {state.isGenerating ? <><Loader2 className="w-5 h-5 animate-spin" /> Composing colors...</> : <><Sparkles className="w-5 h-5" /> Manifest Design</>}
              </button>

              {state.error && <div className="text-red-500 text-sm bg-red-50 p-4 rounded-xl flex items-center gap-2"><AlertCircle className="w-4 h-4" /> {safeStr(state.error)}</div>}
            </div>
          </div>

          <div className="lg:sticky lg:top-28 h-fit">
            {state.isGenerating ? (
              <div className="aspect-[4/5] bg-stone-100 rounded-[2rem] flex flex-col items-center justify-center p-12 text-center animate-pulse border border-stone-200">
                <div className="w-16 h-16 bg-stone-200 rounded-full flex items-center justify-center mb-6">
                  <Palette className="w-8 h-8 text-stone-400" />
                </div>
                <p className="text-xl serif italic text-stone-400">Layering the soul of the poem...</p>
              </div>
            ) : state.result ? (
              <div className="space-y-10 animate-in fade-in duration-1000 slide-in-from-bottom-4">
                {state.result.imageUrl && (
                  <div className="aspect-[4/5] rounded-[2rem] overflow-hidden shadow-2xl border border-stone-100 relative group bg-white">
                    <img src={state.result.imageUrl} alt="" className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105" />
                    <button 
                      onClick={() => toggleFavorite(state.result!)} 
                      className={`absolute bottom-6 right-6 p-4 rounded-full shadow-lg backdrop-blur-sm transition-all transform active:scale-90 ${isFavorited ? 'bg-red-500 text-white' : 'bg-white/80 text-stone-400 hover:bg-white hover:text-red-400'}`}
                    >
                      <Heart className={`w-6 h-6 ${isFavorited ? 'fill-current' : ''}`} />
                    </button>
                  </div>
                )}

                <div className="space-y-12 px-2">
                  <div className="space-y-4">
                    <h3 className="text-5xl font-light italic text-stone-800 tracking-tight">{safeStr(state.result.title)}</h3>
                    <p className="text-stone-500 font-light italic leading-relaxed border-l-2 border-stone-200 pl-6 text-lg">
                      {safeStr(state.result.visualDescription)}
                    </p>
                  </div>

                  <div className="space-y-6">
                    <h4 className="text-[10px] uppercase tracking-[0.3em] font-bold text-stone-400 border-b border-stone-100 pb-2">The Impressionist Palette</h4>
                    <div className="grid grid-cols-4 gap-6">
                      {state.result.colorRecipes.map((c, i) => (
                        <div key={i} className="space-y-3 group">
                          <div className="w-full aspect-square rounded-2xl shadow-inner border border-stone-100 transform transition-transform group-hover:-translate-y-1" style={{ backgroundColor: safeStr(c.hex) }} />
                          <div className="text-[10px] uppercase font-bold text-stone-800 leading-tight">{safeStr(c.name)}</div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="bg-white p-10 rounded-[2.5rem] border border-stone-100 shadow-sm space-y-10">
                    <div className="space-y-6">
                      <div className="flex items-center gap-2">
                        <Droplets className="w-4 h-4 text-stone-300" />
                        <h4 className="text-xs uppercase tracking-[0.2em] font-bold text-stone-800">Peotraco Mixing Guide</h4>
                      </div>
                      <div className="space-y-6">
                        {state.result.colorRecipes.map((c, i) => (
                          <div key={i} className="flex gap-6 group">
                            <div className="w-12 h-12 rounded-full flex-shrink-0 shadow-md border-2 border-white ring-1 ring-stone-100" style={{ backgroundColor: safeStr(c.hex) }} />
                            <div className="flex-1 space-y-1">
                              <span className="text-[11px] uppercase tracking-wider font-bold text-stone-700">{safeStr(c.name)}</span>
                              <p className="text-sm text-stone-500 font-light italic leading-relaxed">{safeStr(c.recipe)}</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="pt-10 border-t border-stone-50">
                      <div className="flex items-center gap-2 mb-4">
                        <Palette className="w-4 h-4 text-stone-300" />
                        <h4 className="text-xs uppercase tracking-[0.2em] font-bold text-stone-800">Spatula Technique</h4>
                      </div>
                      <p className="text-sm text-stone-500 font-light leading-relaxed italic">{safeStr(state.result.technique)}</p>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="aspect-[4/5] bg-stone-50/50 rounded-[2rem] border-2 border-dashed border-stone-100 flex flex-col items-center justify-center p-12 text-center text-stone-300">
                <Feather className="w-12 h-12 mb-4 opacity-20" />
                <p className="text-sm font-light italic">Your design will manifest here once the poem is composed.</p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

export interface ColorRecipe {
  name: string;
  hex: string;
  recipe: string;
}

export interface CakeDesign {
  id: string;
  timestamp: number;
  title: string;
  visualDescription: string;
  technique: string;
  colorRecipes: ColorRecipe[];
  imageUrl?: string;
  isShared?: boolean; // Flag for imported designs
}

export interface AppState {
  isGenerating: boolean;
  result: CakeDesign | null;
  error: string | null;
}

import React, { useState, useEffect, useMemo } from 'react';
import { Palette, Feather, Sparkles, Image as ImageIcon, Loader2, Camera, ArrowRight, X, AlertCircle, Heart, Trash2, BookOpen, Info, Droplets, Share2, Check, Copy } from 'lucide-react';
import { generateCakeDesign } from './services/geminiService';
import { AppState, CakeDesign } from './types';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [imageFile, setImageFile] = useState<string | null>(null);
  const [state, setState] = useState<AppState>({
    isGenerating: false,
    result: null,
    error: null
  });
  const [hasKey, setHasKey] = useState<boolean | null>(null);
  const [favorites, setFavorites] = useState<CakeDesign[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);
  const [showLogic, setShowLogic] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);

  // Persistence: Load from LocalStorage and handle Shared Links
  useEffect(() => {
    // 1. Load favorites
    const saved = localStorage.getItem('qp_favorites_v2');
    if (saved) {
      try {
        setFavorites(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load favorites", e);
      }
    }

    // 2. Handle Shared Link (Interconnected Experience)
    const hash = window.location.hash;
    if (hash && hash.length > 1) {
      try {
        const encodedData = hash.substring(1);
        const decodedData = JSON.parse(decodeURIComponent(atob(encodedData)));
        if (decodedData && decodedData.title) {
          const sharedDesign = { ...decodedData, isShared: true };
          setState(prev => ({ ...prev, result: sharedDesign }));
          // Clear hash to keep URL clean, but keep design in state
          window.history.replaceState(null, '', window.location.pathname);
        }
      } catch (e) {
        console.error("Failed to decode shared design", e);
      }
    }
  }, []);

  // Save to LocalStorage whenever favorites change
  useEffect(() => {
    localStorage.setItem('qp_favorites_v2', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const studio = (window as any).aistudio;
        if (studio && typeof studio.hasSelectedApiKey === 'function') {
          const selected = await studio.hasSelectedApiKey();
          setHasKey(selected);
        } else {
          setHasKey(true); 
        }
      } catch (e) {
        setHasKey(false);
      }
    };
    checkKey();
  }, []);

  const handleKeySelect = async () => {
    try {
      const studio = (window as any).aistudio;
      if (studio && typeof studio.openSelectKey === 'function') {
        await studio.openSelectKey();
        setHasKey(true);
      }
    } catch (e) {
      console.error("Key selection failed", e);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    try {
      const result = await generateCakeDesign(prompt || "Create an impressionist cake masterpiece.", imageFile || undefined);
      const resultWithMeta: CakeDesign = {
        ...result,
        id: Math.random().toString(36).substring(2, 9),
        timestamp: Date.now()
      };
      setState({ isGenerating: false, result: resultWithMeta, error: null });
    } catch (err: any) {
      if (err.message === "API_KEY_ERROR") {
        setHasKey(false);
        setState(prev => ({ ...prev, isGenerating: false, error: "Authentication required. Please select a Studio key." }));
      } else {
        setState(prev => ({ ...prev, isGenerating: false, error: "The mist has settled unexpectedly. Please try again." }));
      }
    }
  };

  const toggleFavorite = (design: CakeDesign) => {
    const isFav = favorites.some(f => f.title === design.title && f.visualDescription === design.visualDescription);
    if (isFav) {
      setFavorites(favorites.filter(f => !(f.title === design.title && f.visualDescription === design.visualDescription)));
    } else {
      setFavorites([design, ...favorites]);
    }
  };

  const shareDesign = (design: CakeDesign) => {
    try {
      // Exclude image from URL to avoid exceeding URL length limits (images stay in local context)
      // If we had a backend, we'd store the image there. For now, we share the "Poem" data.
      const { imageUrl, ...shareableData } = design;
      const encoded = btoa(encodeURIComponent(JSON.stringify(shareableData)));
      const url = `${window.location.origin}${window.location.pathname}#${encoded}`;

      navigator.clipboard.writeText(url);
      setCopyStatus(design.id);
      setTimeout(() => setCopyStatus(null), 2000);
    } catch (e) {
      console.error("Failed to share", e);
    }
  };

  const isFavorited = useMemo(() => {
    if (!state.result) return false;
    return favorites.some(f => f.title === state.result?.title && f.visualDescription === state.result?.visualDescription);
  }, [state.result, favorites]);

  const safeStr = (val: any) => (typeof val === 'string' ? val : (val ? JSON.stringify(val) : ''));

  if (hasKey === false) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#faf9f6] p-4">
        <div className="max-w-md w-full text-center space-y-8 bg-white p-10 rounded-3xl shadow-sm border border-stone-100">
          <div className="flex justify-center">
            <div className="p-4 bg-stone-50 rounded-full">
              <Palette className="w-12 h-12 text-stone-400 stroke-1" />
            </div>
          </div>
          <div className="space-y-2">
            <h1 className="text-4xl font-light tracking-tight text-stone-800">Quille en Poème</h1>
            <p className="text-stone-500 font-light">To unlock the studio, please select your payment-ready API key.</p>
          </div>
          <button
            onClick={handleKeySelect}
            className="w-full py-4 bg-stone-800 text-white rounded-xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-2 group"
          >
            Select Studio Key
            <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 relative bg-[#faf9f6]">
      <nav className="sticky top-0 z-50 ethereal-blur border-b border-stone-100 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-stone-800 rounded-full flex items-center justify-center">
            <span className="text-white text-xs font-serif italic">QP</span>
          </div>
          <h1 className="text-xl tracking-widest uppercase font-light text-stone-800">Quille en Poème</h1>
        </div>
        <div className="flex items-center gap-4 text-xs tracking-widest uppercase text-stone-500 font-medium">
          <button 
            onClick={() => setShowFavorites(!showFavorites)} 
            className="px-4 py-2 bg-white rounded-full border border-stone-100 shadow-sm hover:shadow-md transition-all flex items-center gap-2 group"
          >
            <BookOpen className="w-4 h-4 text-stone-400 group-hover:text-stone-800" />
            Collection ({favorites.length})
          </button>
        </div>
      </nav>

