import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign } from "../types";

export const generateCakeDesign = async (prompt: string, imageData?: string): Promise<CakeDesign> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any[] = [{ text: prompt }];
  if (imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: imageData.split(',')[1]
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        },
      },
    });

    let cakeData: any = {};
    let imageUrl: string | undefined;

    // Use response.text property directly as per guidelines
    const fullText = response.text || "";
    try {
      const cleanedText = fullText.replace(/```json|```/g, '').trim();
      cakeData = JSON.parse(cleanedText);
    } catch (e) {
      console.error("Failed to parse JSON response text", e, fullText);
    }

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    // Explicitly sanitize and cast types to prevent Error #31
    // Added id and timestamp to satisfy the mandatory fields in CakeDesign interface
    return {
      id: Math.random().toString(36).substring(2, 9),
      timestamp: Date.now(),
      title: typeof cakeData.title === 'string' ? cakeData.title : "Untitled Creation",
      visualDescription: typeof cakeData.visualDescription === 'string' ? cakeData.visualDescription : "A delicate mist-filled design.",
      technique: typeof cakeData.technique === 'string' ? cakeData.technique : "Spatula work with soft strokes.",
      colorRecipes: Array.isArray(cakeData.colorRecipes) ? cakeData.colorRecipes.map((c: any) => ({
        name: String(c.name || 'Pale Shade'),
        hex: String(c.hex || '#faf9f6'),
        recipe: String(c.recipe || 'Mix with care.')
      })) : [],
      imageUrl: imageUrl
    };
  } catch (error: any) {
    if (error.message?.includes("Requested entity was not found")) {
      throw new Error("API_KEY_ERROR");
    }
    throw error;
  }
};

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign } from "../types";

export const generateCakeDesign = async (prompt: string, imageData?: string): Promise<CakeDesign> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any[] = [{ text: prompt }];
  if (imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: imageData.split(',')[1]
      }
    });
  }

  // Primary attempt with Pro model
  try {
    return await callModel(ai, 'gemini-3-pro-image-preview', contents);
  } catch (error: any) {
    const errorMsg = error.message || "";
    // If credit/quota issue (429, 403) or generic failure, fallback to Flash Image (standard/free-tier friendly)
    if (errorMsg.includes("429") || errorMsg.includes("403") || errorMsg.includes("quota") || errorMsg.includes("limit")) {
      console.warn("Primary model failed or quota exceeded. Falling back to standard tier...");
      try {
        return await callModel(ai, 'gemini-2.5-flash-image', contents);
      } catch (fallbackError) {
        console.error("Fallback model also failed", fallbackError);
        throw fallbackError;
      }
    }
    throw error;
  }
};

async function callModel(ai: any, modelName: string, contents: any[]): Promise<CakeDesign> {
  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: contents },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: "1K"
      },
    },
  });

  let cakeData: any = {};
  let imageUrl: string | undefined;

  const fullText = response.text || "";
  try {
    const cleanedText = fullText.replace(/```json|```/g, '').trim();
    cakeData = JSON.parse(cleanedText);
  } catch (e) {
    console.error("Failed to parse JSON response text", e, fullText);
    // Basic structural fallback if JSON fails
    cakeData = {
      title: "Vision Éphémère",
      visualDescription: fullText.substring(0, 200) + "...",
      technique: "Technique de spatule douce."
    };
  }

  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }

  return {
    id: Math.random().toString(36).substring(2, 9),
    timestamp: Date.now(),
    title: typeof cakeData.title === 'string' ? cakeData.title : "Untitled Creation",
    visualDescription: typeof cakeData.visualDescription === 'string' ? cakeData.visualDescription : "A delicate mist-filled design.",
    technique: typeof cakeData.technique === 'string' ? cakeData.technique : "Spatula work with soft strokes.",
    colorRecipes: Array.isArray(cakeData.colorRecipes) ? cakeData.colorRecipes.map((c: any) => ({
      name: String(c.name || 'Pale Shade'),
      hex: String(c.hex || '#faf9f6'),
      recipe: String(c.recipe || 'Mix with care.')
    })) : [],
    imageUrl: imageUrl
  };
}

import React, { useState, useEffect, useMemo } from 'react';
import { Palette, Feather, Sparkles, Image as ImageIcon, Loader2, Camera, ArrowRight, X, AlertCircle, Heart, Trash2, BookOpen, Info, Droplets, Share2, Check, Copy, Globe } from 'lucide-react';
import { generateCakeDesign } from './services/geminiService';
import { AppState, CakeDesign } from './types';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [imageFile, setImageFile] = useState<string | null>(null);
  const [state, setState] = useState<AppState>({
    isGenerating: false,
    result: null,
    error: null
  });
  const [hasKey, setHasKey] = useState<boolean | null>(null);
  const [favorites, setFavorites] = useState<CakeDesign[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);
  const [showLogic, setShowLogic] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [isFallbackMode, setIsFallbackMode] = useState(false);

  // Persistence: Load from LocalStorage and handle Shared Links
  useEffect(() => {
    // 1. Load favorites
    const saved = localStorage.getItem('qp_favorites_v2');
    if (saved) {
      try {
        setFavorites(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load favorites", e);
      }
    }

    // 2. Handle Shared Link (Interconnected Experience)
    const handleSharedLink = () => {
      const hash = window.location.hash;
      if (hash && hash.length > 1) {
        try {
          const encodedData = hash.substring(1);
          // Decode URL safe base64
          const decodedData = JSON.parse(decodeURIComponent(atob(encodedData)));
          if (decodedData && decodedData.title) {
            const sharedDesign = { ...decodedData, isShared: true };
            setState(prev => ({ ...prev, result: sharedDesign }));
            // Open panel if it's a shared link to show the context
            setShowFavorites(true);
          }
        } catch (e) {
          console.error("Failed to decode shared design", e);
        }
      }
    };

    handleSharedLink();
    window.addEventListener('hashchange', handleSharedLink);
    return () => window.removeEventListener('hashchange', handleSharedLink);
  }, []);

  // Save to LocalStorage whenever favorites change
  useEffect(() => {
    localStorage.setItem('qp_favorites_v2', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const studio = (window as any).aistudio;
        if (studio && typeof studio.hasSelectedApiKey === 'function') {
          const selected = await studio.hasSelectedApiKey();
          setHasKey(selected);
        } else {
          setHasKey(true); 
        }
      } catch (e) {
        setHasKey(false);
      }
    };
    checkKey();
  }, []);

  const handleKeySelect = async () => {
    try {
      const studio = (window as any).aistudio;
      if (studio && typeof studio.openSelectKey === 'function') {
        await studio.openSelectKey();
        setHasKey(true);
      }
    } catch (e) {
      console.error("Key selection failed", e);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    setIsFallbackMode(false);

    try {
      const result = await generateCakeDesign(prompt || "Create an impressionist cake masterpiece.", imageFile || undefined);
      setState({ isGenerating: false, result: result, error: null });
    } catch (err: any) {
      const errorMsg = err.message || "";
      if (errorMsg === "API_KEY_ERROR") {
        setHasKey(false);
        setState(prev => ({ ...prev, isGenerating: false, error: "Authentication required. Please select a Studio key." }));
      } else if (errorMsg.includes("429") || errorMsg.includes("quota") || errorMsg.includes("limit")) {
         setIsFallbackMode(true);
         setState(prev => ({ ...prev, isGenerating: false, error: "The Studio is crowded. Switching to standard composition mode..." }));
         // Wait a second and try the fallback manually if service logic didn't handle it
         setTimeout(handleGenerate, 1500);
      } else {
        setState(prev => ({ ...prev, isGenerating: false, error: "The mist has settled unexpectedly. Please try again." }));
      }
    }
  };

  const toggleFavorite = (design: CakeDesign) => {
    const isFav = favorites.some(f => f.title === design.title && f.visualDescription === design.visualDescription);
    if (isFav) {
      setFavorites(favorites.filter(f => !(f.title === design.title && f.visualDescription === design.visualDescription)));
    } else {
      // Remove 'isShared' flag when saving locally to mark it as part of personal collection
      const toSave = { ...design, isShared: false, timestamp: Date.now() };
      setFavorites([toSave, ...favorites]);
    }
  };

  const shareDesign = (design: CakeDesign) => {
    try {
      // Exclude large image data to keep URL length manageable
      const { imageUrl, ...shareableData } = design;
      const encoded = btoa(encodeURIComponent(JSON.stringify(shareableData)));
      const url = `${window.location.origin}${window.location.pathname}#${encoded}`;

      navigator.clipboard.writeText(url);
      setCopyStatus(design.id);
      setTimeout(() => setCopyStatus(null), 2000);
    } catch (e) {
      console.error("Failed to share", e);
    }
  };

  const isFavorited = useMemo(() => {
    if (!state.result) return false;
    return favorites.some(f => f.title === state.result?.title && f.visualDescription === state.result?.visualDescription);
  }, [state.result, favorites]);

  const safeStr = (val: any) => (typeof val === 'string' ? val : (val ? JSON.stringify(val) : ''));

  if (hasKey === false) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#faf9f6] p-4">
        <div className="max-w-md w-full text-center space-y-8 bg-white p-10 rounded-3xl shadow-sm border border-stone-100">
          <div className="flex justify-center">
            <div className="p-4 bg-stone-50 rounded-full">
              <Palette className="w-12 h-12 text-stone-400 stroke-1" />
            </div>
          </div>
          <div className="space-y-2">
            <h1 className="text-4xl font-light tracking-tight text-stone-800">Quille en Poème</h1>
            <p className="text-stone-500 font-light">To unlock the studio, please select your payment-ready API key.</p>
          </div>
          <button
            onClick={handleKeySelect}
            className="w-full py-4 bg-stone-800 text-white rounded-xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-2 group"
          >
            Select Studio Key
            <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 relative bg-[#faf9f6]">
      <nav className="sticky top-0 z-50 ethereal-blur border-b border-stone-100 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-stone-800 rounded-full flex items-center justify-center">
            <span className="text-white text-xs font-serif italic">QP</span>
          </div>
          <h1 className="text-xl tracking-widest uppercase font-light text-stone-800">Quille en Poème</h1>
        </div>
        <div className="flex items-center gap-4 text-xs tracking-widest uppercase text-stone-500 font-medium">
          {isFallbackMode && (
            <span className="hidden md:flex items-center gap-2 text-amber-600 bg-amber-50 px-3 py-1 rounded-full border border-amber-100 animate-pulse">
              <Sparkles className="w-3 h-3" /> Standard Tier Active
            </span>
          )}
          <button 
            onClick={() => setShowFavorites(!showFavorites)} 
            className="px-4 py-2 bg-white rounded-full border border-stone-100 shadow-sm hover:shadow-md transition-all flex items-center gap-2 group"
          >
            <BookOpen className="w-4 h-4 text-stone-400 group-hover:text-stone-800" />
            Museum Collection ({favorites.length})
          </button>
        </div>
      </nav>

      {/* Logic Reference Panel */}
      <div className={`fixed inset-y-0 left-0 w-full md:w-80 bg-white z-[60] shadow-2xl transition-transform duration-500 ease-out border-r border-stone-100 flex flex-col ${showLogic ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 border-b border-stone-100 flex justify-between items-center">
          <h3 className="text-sm tracking-widest uppercase font-bold text-stone-800">Mixing Philosophy</h3>
          <button onClick={() => setShowLogic(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors"><X className="w-4 h-4" /></button>
        </div>
        <div className="p-6 space-y-8 overflow-y-auto">
          <div className="space-y-4">
            <h4 className="text-xs uppercase tracking-widest font-bold text-stone-400">The Peotraco Set</h4>
            <div className="flex flex-wrap gap-2">
              {["Orange", "Black", "Green", "White", "Red", "Brown", "Yellow", "Blue"].map(c => (
                <span key={c} className="px-2 py-1 bg-stone-50 text-[10px] rounded-md border border-stone-100 text-stone-600 font-medium">{c}</span>
              ))}
            </div>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Dusty / Muted Tones</h4>
              <p className="text-xs text-stone-500 font-light leading-relaxed">Base Color + touch of Brown + plenty of White.</p>
            </div>
            <div className="space-y-2">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Vintage Greens</h4>
              <p className="text-xs text-stone-500 font-light leading-relaxed">Green + touch of Orange (to kill neon) + White.</p>
            </div>
            <div className="space-y-2">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Twilight Purples</h4>
              <p className="text-xs text-stone-500 font-light leading-relaxed">Blue + Red + touch of Black + White.</p>
            </div>
            <div className="space-y-2">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Champagne / Cream</h4>
              <p className="text-xs text-stone-500 font-light leading-relaxed">White + tiny dot of Yellow + tiny dot of Brown.</p>
            </div>
          </div>
        </div>
      </div>

      {/* Persistent Collection Side Panel */}
      <div className={`fixed inset-y-0 right-0 w-full md:w-96 bg-[#faf9f6] z-[60] shadow-2xl transition-transform duration-500 ease-out border-l border-stone-100 flex flex-col ${showFavorites ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-6 bg-white border-b border-stone-100 flex justify-between items-center">
          <div className="space-y-1">
            <h3 className="text-xl tracking-widest uppercase font-light text-stone-800">Museum Gallery</h3>
