          </div>
          <button onClick={() => setShowFavorites(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors"><X className="w-5 h-5 text-stone-400" /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {favorites.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-6 px-12 opacity-40">
