                />
              </div>

              <div className="space-y-3">
                <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-stone-400 flex items-center gap-2"><ImageIcon className="w-3 h-3" /> Botanical Soul</label>
                <div className="relative group">
                  {imageFile ? (
                    <div className="relative aspect-video rounded-2xl overflow-hidden shadow-inner">
                      <img src={imageFile} alt="Reference" className="w-full h-full object-cover" />
                      <button onClick={() => setImageFile(null)} className="absolute top-3 right-3 p-1.5 bg-black/40 text-white rounded-full backdrop-blur-md hover:bg-black/60 transition-colors"><X className="w-4 h-4" /></button>
                    </div>
                  ) : (
                    <label className="flex flex-col items-center justify-center w-full aspect-video border-2 border-dashed border-stone-200 rounded-2xl cursor-pointer hover:bg-stone-50 hover:border-stone-300 transition-all">
                      <Camera className="w-8 h-8 text-stone-300 mb-3" />
                      <p className="text-sm text-stone-400 font-light">Upload photo or texture</p>
                      <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                    </label>
                  )}
                </div>
              </div>

              <button
                disabled={state.isGenerating || (!prompt && !imageFile)}
                onClick={handleGenerate}
                className="w-full py-5 bg-stone-800 text-white rounded-2xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-3 disabled:opacity-50"
              >
                {state.isGenerating ? <><Loader2 className="w-5 h-5 animate-spin" /> Composing colors...</> : <><Sparkles className="w-5 h-5" /> Manifest Design</>}
              </button>

              {state.error && <div className={`text-sm p-4 rounded-xl flex items-center gap-2 ${isFallbackMode ? 'text-amber-600 bg-amber-50' : 'text-red-500 bg-red-50'}`}><AlertCircle className="w-4 h-4" /> {safeStr(state.error)}</div>}
            </div>
          </div>

          <div className="lg:sticky lg:top-28 h-fit">
            {state.isGenerating ? (
              <div className="aspect-[4/5] bg-stone-100 rounded-[2rem] flex flex-col items-center justify-center p-12 text-center animate-pulse border border-stone-200">
                <div className="w-16 h-16 bg-stone-200 rounded-full flex items-center justify-center mb-6">
                  <Palette className="w-8 h-8 text-stone-400" />
                </div>
                <p className="text-xl serif italic text-stone-400">Layering the soul of the poem...</p>
              </div>
            ) : state.result ? (
              <div className="space-y-10 animate-in fade-in duration-1000 slide-in-from-bottom-4">
                {state.result.isShared && (
                  <div className="bg-stone-800 text-white p-6 rounded-[2rem] flex items-center justify-between shadow-xl">
                    <div className="flex items-center gap-4">
                      <div className="p-2 bg-stone-700 rounded-full">
                        <Globe className="w-5 h-5 text-stone-300" />
                      </div>
                      <div className="space-y-1">
                        <p className="text-[10px] uppercase font-bold tracking-[0.2em] text-stone-400">Imported Design</p>
                        <p className="text-sm font-light italic">Preserving this shared inspiration.</p>
                      </div>
                    </div>
                    {!isFavorited && (
                      <button 
                        onClick={() => toggleFavorite(state.result!)}
                        className="px-5 py-2.5 bg-white text-stone-800 text-[10px] uppercase font-bold rounded-xl shadow-sm hover:bg-stone-100 transition-colors"
                      >
                        Add to Collection
                      </button>
                    )}
                  </div>
                )}

                {state.result.imageUrl ? (
                  <div className="aspect-[4/5] rounded-[2rem] overflow-hidden shadow-2xl border border-stone-100 relative group bg-white">
                    <img src={state.result.imageUrl} alt="" className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105" />
                    <div className="absolute bottom-6 right-6 flex gap-3">
                       <button 
                        onClick={() => shareDesign(state.result!)} 
                        className={`p-4 rounded-full shadow-lg backdrop-blur-sm transition-all transform active:scale-90 bg-white/80 text-stone-400 hover:bg-white hover:text-stone-800`}
                        title="Copy Share Link"
                      >
                        {copyStatus === state.result.id ? <Check className="w-6 h-6 text-green-500" /> : <Copy className="w-6 h-6" />}
                      </button>
                      <button 
                        onClick={() => toggleFavorite(state.result!)} 
                        className={`p-4 rounded-full shadow-lg backdrop-blur-sm transition-all transform active:scale-90 ${isFavorited ? 'bg-red-500 text-white' : 'bg-white/80 text-stone-400 hover:bg-white hover:text-red-400'}`}
                      >
                        <Heart className={`w-6 h-6 ${isFavorited ? 'fill-current' : ''}`} />
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="aspect-[4/5] rounded-[2rem] bg-stone-50 border-2 border-dashed border-stone-200 flex flex-col items-center justify-center p-12 text-center text-stone-300">
                    <ImageIcon className="w-12 h-12 mb-4 opacity-10" />
