import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign } from "../types";

export const generateCakeDesign = async (prompt: string, imageData?: string): Promise<CakeDesign> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any[] = [{ text: prompt }];
  if (imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: imageData.split(',')[1]
      }
    });
  }

  // 1. Try Premium tier first (Pro)
  try {
    return await callModel(ai, 'gemini-3-pro-image-preview', contents);
  } catch (error: any) {
    const errorMsg = (error.message || "").toLowerCase();

    // If credit/quota issue OR lack of specific Pro key (429, 403, 404/not found), fallback to standard tier
    if (
      errorMsg.includes("429") || 
      errorMsg.includes("403") || 
      errorMsg.includes("quota") || 
      errorMsg.includes("limit") || 
      errorMsg.includes("not found") || 
      errorMsg.includes("invalid")
    ) {
      console.warn("Switching to standard composition tier due to high demand or access requirements.");
      try {
        // Fallback to Flash model which is more resilient for general key availability
        return await callModel(ai, 'gemini-2.5-flash-image', contents);
      } catch (fallbackError) {
        console.error("Standard tier also exhausted.", fallbackError);
        throw fallbackError;
      }
    }
    throw error;
  }
};

async function callModel(ai: any, modelName: string, contents: any[]): Promise<CakeDesign> {
  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: contents },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: "1K"
      },
    },
  });

  let cakeData: any = {};
  let imageUrl: string | undefined;

  const fullText = response.text || "";
  try {
    const cleanedText = fullText.replace(/```json|```/g, '').trim();
    cakeData = JSON.parse(cleanedText);
  } catch (e) {
    console.error("Design parsing fallback.", e);
    cakeData = {
      title: "L'Essence du Poème",
      visualDescription: fullText.substring(0, 200),
      technique: "Spatula work with impressionist blending."
    };
  }

  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }

  return {
    id: Math.random().toString(36).substring(2, 9),
    timestamp: Date.now(),
    title: typeof cakeData.title === 'string' ? cakeData.title : "Untitled Creation",
    visualDescription: typeof cakeData.visualDescription === 'string' ? cakeData.visualDescription : "A soulful, mist-inspired design.",
    technique: typeof cakeData.technique === 'string' ? cakeData.technique : "Soft spatula strokes.",
    colorRecipes: Array.isArray(cakeData.colorRecipes) ? cakeData.colorRecipes.map((c: any) => ({
      name: String(c.name || 'Mist'),
      hex: String(c.hex || '#ffffff'),
      recipe: String(c.recipe || 'Mix with White.')
    })) : [],
    imageUrl: imageUrl
  };
}

