  };
}

import React, { useState, useEffect, useMemo } from 'react';
import { Palette, Feather, Sparkles, Image as ImageIcon, Loader2, Camera, ArrowRight, X, AlertCircle, Heart, Trash2, BookOpen, Info, Droplets, Share2, Check, Copy, Globe, Layers, Layout, Brush } from 'lucide-react';
import { generateCakeDesign } from './services/geminiService';
import { AppState, CakeDesign, StudioMode } from './types';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [pastryFormat, setPastryFormat] = useState('');
  const [theme, setTheme] = useState('');
  const [mode, setMode] = useState<StudioMode>('poetic');
  const [imageFile, setImageFile] = useState<string | null>(null);
  const [state, setState] = useState<AppState>({
    isGenerating: false,
    result: null,
    error: null
  });
  const [favorites, setFavorites] = useState<CakeDesign[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);
  const [showLogic, setShowLogic] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [isFallbackMode, setIsFallbackMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('qp_favorites_v2');
    if (saved) {
      try {
        setFavorites(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load favorites", e);
      }
    }

    const handleSharedLink = () => {
      const hash = window.location.hash;
      if (hash && hash.length > 1) {
        try {
          const encodedData = hash.substring(1);
          const decodedData = JSON.parse(decodeURIComponent(atob(encodedData)));
          if (decodedData && decodedData.title) {
            const sharedDesign = { ...decodedData, isShared: true };
            setState(prev => ({ ...prev, result: sharedDesign }));
            setShowFavorites(true);
          }
        } catch (e) {
          console.error("Failed to decode shared design", e);
        }
      }
    };

    handleSharedLink();
    window.addEventListener('hashchange', handleSharedLink);
    return () => window.removeEventListener('hashchange', handleSharedLink);
  }, []);

  useEffect(() => {
    localStorage.setItem('qp_favorites_v2', JSON.stringify(favorites));
  }, [favorites]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    setIsFallbackMode(false);

    try {
      const result = await generateCakeDesign({
        prompt,
        imageData: imageFile || undefined,
        pastryFormat,
        theme,
        mode
      });
      setState({ isGenerating: false, result: result, error: null });
    } catch (err: any) {
      const errorMsg = err.message || "";
      if (errorMsg.includes("429") || errorMsg.includes("quota") || errorMsg.includes("limit") || errorMsg.includes("403") || errorMsg.includes("not found")) {
         setIsFallbackMode(true);
         setState(prev => ({ ...prev, isGenerating: false, error: "High-capacity tier busy. Using standard composition mode..." }));
         setTimeout(handleGenerate, 2000); // Retry once on fallback
      } else {
        setState(prev => ({ ...prev, isGenerating: false, error: "The mist has settled unexpectedly. Please try again." }));
      }
    }
  };

  const toggleFavorite = (design: CakeDesign) => {
    const isFav = favorites.some(f => f.title === design.title && f.visualDescription === design.visualDescription);
    if (isFav) {
      setFavorites(favorites.filter(f => !(f.title === design.title && f.visualDescription === design.visualDescription)));
    } else {
      const toSave = { ...design, isShared: false, timestamp: Date.now() };
      setFavorites([toSave, ...favorites]);
    }
  };

  const shareDesign = (design: CakeDesign) => {
    try {
      const { imageUrl, ...shareableData } = design;
      const encoded = btoa(encodeURIComponent(JSON.stringify(shareableData)));
      const url = `${window.location.origin}${window.location.pathname}#${encoded}`;

      navigator.clipboard.writeText(url);
      setCopyStatus(design.id);
      setTimeout(() => setCopyStatus(null), 2000);
    } catch (e) {
      console.error("Failed to share", e);
    }
  };

  const isFavorited = useMemo(() => {
    if (!state.result) return false;
    return favorites.some(f => f.title === state.result?.title && f.visualDescription === state.result?.visualDescription);
  }, [state.result, favorites]);

  const safeStr = (val: any) => (typeof val === 'string' ? val : (val ? JSON.stringify(val) : ''));

  return (
    <div className="min-h-screen pb-20 relative bg-[#faf9f6]">
      <nav className="sticky top-0 z-50 ethereal-blur border-b border-stone-100 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-stone-800 rounded-full flex items-center justify-center">
            <span className="text-white text-xs font-serif italic">QP</span>
          </div>
          <h1 className="text-xl tracking-widest uppercase font-light text-stone-800">Quille en Poème</h1>
        </div>
        <div className="flex items-center gap-4 text-xs tracking-widest uppercase text-stone-500 font-medium">
          <button 
            onClick={() => setShowFavorites(!showFavorites)} 
            className="px-4 py-2 bg-white rounded-full border border-stone-100 shadow-sm hover:shadow-md transition-all flex items-center gap-2 group"
          >
            <BookOpen className="w-4 h-4 text-stone-400 group-hover:text-stone-800" />
            Le Musée ({favorites.length})
          </button>
        </div>
      </nav>

      {/* Logic Panel */}
      <div className={`fixed inset-y-0 left-0 w-full md:w-80 bg-white z-[60] shadow-2xl transition-transform duration-500 ease-out border-r border-stone-100 flex flex-col ${showLogic ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 border-b border-stone-100 flex justify-between items-center">
          <h3 className="text-sm tracking-widest uppercase font-bold text-stone-800">Mixing Philosophy</h3>
          <button onClick={() => setShowLogic(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors"><X className="w-4 h-4" /></button>
        </div>
        <div className="p-6 space-y-8 overflow-y-auto">
          <div className="space-y-4">
            <h4 className="text-xs uppercase tracking-widest font-bold text-stone-400">The Peotraco Set</h4>
            <div className="flex flex-wrap gap-2">
              {["Orange", "Black", "Green", "White", "Red", "Brown", "Yellow", "Blue"].map(c => (
                <span key={c} className="px-2 py-1 bg-stone-50 text-[10px] rounded-md border border-stone-100 text-stone-600 font-medium">{c}</span>
              ))}
            </div>
          </div>
          <div className="space-y-6 text-stone-500 text-xs font-light leading-relaxed">
            <div className="space-y-1">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Dusty / Muted Tones</h4>
              <p>Base + Brown + White.</p>
            </div>
            <div className="space-y-1">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Vintage Greens</h4>
              <p>Green + Orange + White.</p>
            </div>
            <div className="space-y-1">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Twilight Purples</h4>
              <p>Blue + Red + Black + White.</p>
            </div>
            <div className="space-y-1">
              <h4 className="text-[10px] uppercase font-bold text-stone-800">Champagne</h4>
              <p>White + Yellow (dot) + Brown (dot).</p>
            </div>
          </div>
        </div>
      </div>

      {/* Museum Side Panel */}
      <div className={`fixed inset-y-0 right-0 w-full md:w-96 bg-[#faf9f6] z-[60] shadow-2xl transition-transform duration-500 ease-out border-l border-stone-100 flex flex-col ${showFavorites ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-6 bg-white border-b border-stone-100 flex justify-between items-center">
          <div className="space-y-1">
            <h3 className="text-xl tracking-widest uppercase font-light text-stone-800">Museum Gallery</h3>
            <p className="text-[10px] text-stone-400 uppercase tracking-widest">Permanent Collection</p>
          </div>
          <button onClick={() => setShowFavorites(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors"><X className="w-5 h-5 text-stone-400" /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {favorites.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-6 px-12 opacity-40">
              <Globe className="w-10 h-10 text-stone-300 stroke-1" />
              <p className="text-sm font-light italic text-stone-500 leading-relaxed">Your gallery is empty. Save any design to keep it forever.</p>
            </div>
          ) : (
            favorites.map((fav) => (
              <div key={fav.id} className="bg-white rounded-[2rem] overflow-hidden border border-stone-100 transition-all hover:shadow-xl p-6 space-y-4">
                <div className="flex justify-between items-start">
                  <div className="space-y-1">
                    <h4 className="text-xl serif italic text-stone-800">{safeStr(fav.title)}</h4>
                    <p className="text-[10px] text-stone-400 font-bold uppercase tracking-widest">{new Date(fav.timestamp).toLocaleDateString()}</p>
                  </div>
                  <div className="flex gap-1">
                    <button onClick={() => shareDesign(fav)} className="p-2 text-stone-400 hover:text-stone-800 bg-stone-50 rounded-full">{copyStatus === fav.id ? <Check className="w-4 h-4 text-green-500" /> : <Share2 className="w-4 h-4" />}</button>
                    <button onClick={() => toggleFavorite(fav)} className="p-2 text-stone-300 hover:text-red-400 bg-stone-50 rounded-full"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </div>
                {fav.imageUrl && <img src={fav.imageUrl} alt="" className="w-full aspect-square object-cover rounded-2xl border border-stone-50" />}
                <button 
                  onClick={() => { setState({ ...state, result: fav }); setShowFavorites(false); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
                  className="w-full py-3 bg-stone-50 text-stone-800 rounded-xl text-[10px] uppercase font-bold tracking-widest hover:bg-stone-800 hover:text-white transition-all"
                >
                  Recall Details
                </button>
              </div>
            ))
          )}
        </div>
      </div>

      <main className="max-w-7xl mx-auto px-6 pt-12">
        <div className="grid lg:grid-cols-2 gap-20">
          <div className="space-y-10">
            <header className="space-y-4">
              <h2 className="text-7xl font-light text-stone-800 leading-[0.9]">Sucre en <br /><span className="italic">Poème</span></h2>
              <p className="text-stone-500 max-w-sm font-light leading-relaxed">Artisan Patisserie using Impressionist Spatula Work to translate your soul into flavor and form.</p>
            </header>

            <div className="bg-white p-8 rounded-[2.5rem] border border-stone-100 shadow-sm space-y-8">
              {/* Mode Toggle */}
              <div className="flex p-1 bg-stone-50 rounded-2xl">
                <button 
                  onClick={() => setMode('poetic')}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-[10px] uppercase tracking-widest font-bold transition-all ${mode === 'poetic' ? 'bg-white text-stone-800 shadow-sm' : 'text-stone-400'}`}
                >
                  <Feather className="w-3 h-3" /> Poésie Botanique
                </button>
                <button 
                  onClick={() => setMode('recreation')}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-[10px] uppercase tracking-widest font-bold transition-all ${mode === 'recreation' ? 'bg-white text-stone-800 shadow-sm' : 'text-stone-400'}`}
                >
                  <Brush className="w-3 h-3" /> Étude de Maître
                </button>
              </div>

              <div className="grid md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest font-bold text-stone-400 flex items-center gap-2"><Layout className="w-3 h-3" /> Pastry Format</label>
                  <input 
                    type="text" 
                    value={pastryFormat}
                    onChange={(e) => setPastryFormat(e.target.value)}
                    placeholder="e.g. 6pc Eclair Box, 3-Tier Cake"
                    className="w-full bg-stone-50 border-none rounded-xl p-3 text-xs text-stone-700 outline-none focus:ring-1 focus:ring-stone-200"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest font-bold text-stone-400 flex items-center gap-2"><Sparkles className="w-3 h-3" /> Occasion / Theme</label>
                  <input 
                    type="text" 
                    value={theme}
                    onChange={(e) => setTheme(e.target.value)}
                    placeholder="e.g. Wedding, Cinderella, Corporate"
                    className="w-full bg-stone-50 border-none rounded-xl p-3 text-xs text-stone-700 outline-none focus:ring-1 focus:ring-stone-200"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-stone-400 flex items-center gap-2">
                  {mode === 'poetic' ? <><Feather className="w-3 h-3" /> The Poem</> : <><Layers className="w-3 h-3" /> Subject Analysis</>}
                </label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder={mode === 'poetic' ? "A summer sunset over a wild lavender field..." : "Translate the uploaded image (pet, couple, logo) into impressionist spatula strokes..."}
                  className="w-full h-24 bg-stone-50 border-none rounded-xl p-4 focus:ring-1 focus:ring-stone-200 outline-none text-stone-700 font-light resize-none text-xs"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-stone-400 flex items-center gap-2"><ImageIcon className="w-3 h-3" /> Visual Baseline</label>
                {imageFile ? (
                  <div className="relative aspect-video rounded-2xl overflow-hidden shadow-inner">
                    <img src={imageFile} alt="Reference" className="w-full h-full object-cover" />
                    <button onClick={() => setImageFile(null)} className="absolute top-2 right-2 p-1.5 bg-black/40 text-white rounded-full backdrop-blur-md"><X className="w-3 h-3" /></button>
                  </div>
                ) : (
                  <label className="flex flex-col items-center justify-center w-full aspect-video border-2 border-dashed border-stone-100 rounded-2xl cursor-pointer hover:bg-stone-50 transition-all">
                    <Camera className="w-6 h-6 text-stone-300 mb-2" />
                    <p className="text-[10px] text-stone-400 uppercase tracking-widest font-bold">Upload Reference</p>
                    <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                  </label>
                )}
              </div>

              <button
                disabled={state.isGenerating || (!prompt && !imageFile)}
                onClick={handleGenerate}
                className="w-full py-5 bg-stone-800 text-white rounded-2xl hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-3 disabled:opacity-50"
              >
                {state.isGenerating ? <><Loader2 className="w-5 h-5 animate-spin" /> Composing Design...</> : <><Sparkles className="w-5 h-5" /> Manifest Masterpiece</>}
              </button>

              <button onClick={() => setShowLogic(true)} className="w-full text-[10px] uppercase font-bold text-stone-300 hover:text-stone-800 transition-colors tracking-widest">View Color Philosophy</button>
            </div>
          </div>

          <div className="lg:sticky lg:top-24 h-fit">
            {state.isGenerating ? (
              <div className="aspect-[4/5] bg-stone-100 rounded-[3rem] flex flex-col items-center justify-center p-12 text-center animate-pulse border border-stone-200">
                <Palette className="w-12 h-12 text-stone-300 mb-6" />
                <p className="text-2xl serif italic text-stone-400 leading-relaxed">Mixing the palette of <br />{mode === 'poetic' ? 'the poem' : 'the master study'}...</p>
              </div>
            ) : state.result ? (
              <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
                <div className="relative group">
                  <div className="aspect-[4/5] rounded-[3rem] overflow-hidden shadow-2xl border border-stone-100 bg-white">
                    {state.result.imageUrl ? (
                      <img src={state.result.imageUrl} alt="" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center bg-stone-50 italic text-stone-300">Shared Design View</div>
                    )}
