                    <button onClick={() => toggleFavorite(state.result!)} className={`p-5 rounded-full shadow-xl transition-all ${isFavorited ? 'bg-red-500 text-white' : 'bg-white text-stone-400 hover:text-red-500'}`}><Heart className={`w-6 h-6 ${isFavorited ? 'fill-current' : ''}`} /></button>
