              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Palette, Feather, Sparkles, Image as ImageIcon, Loader2, Camera, ArrowRight, X, AlertCircle, Heart, Trash2, BookOpen, Info, Droplets, Share2, Check, Copy, Globe, Layers, Layout, Brush, HeartHandshake } from 'lucide-react';
import { generateCakeDesign } from './services/geminiService';
import { AppState, CakeDesign, StudioMode } from './types';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [pastryFormat, setPastryFormat] = useState('');
  const [theme, setTheme] = useState('');
  const [mode, setMode] = useState<StudioMode>('poetic');
  const [imageFile, setImageFile] = useState<string | null>(null);
  const [state, setState] = useState<AppState>({
    isGenerating: false,
    result: null,
    error: null
  });
  const [favorites, setFavorites] = useState<CakeDesign[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);
  const [showLogic, setShowLogic] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [isFallbackMode, setIsFallbackMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('qp_favorites_v2');
    if (saved) {
      try {
        setFavorites(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load favorites", e);
      }
    }

    const handleSharedLink = () => {
      const hash = window.location.hash;
      if (hash && hash.length > 1) {
        try {
          const encodedData = hash.substring(1);
          const decodedData = JSON.parse(decodeURIComponent(atob(encodedData)));
          if (decodedData && decodedData.title) {
            const sharedDesign = { ...decodedData, isShared: true };
            setState(prev => ({ ...prev, result: sharedDesign }));
            setShowFavorites(true);
          }
        } catch (e) {
          console.error("Failed to decode shared design", e);
        }
      }
    };

    handleSharedLink();
    window.addEventListener('hashchange', handleSharedLink);
    return () => window.removeEventListener('hashchange', handleSharedLink);
  }, []);

  useEffect(() => {
    localStorage.setItem('qp_favorites_v2', JSON.stringify(favorites));
  }, [favorites]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    setIsFallbackMode(false);

    try {
      const result = await generateCakeDesign({
        prompt: prompt || "An unnamable feeling of peace and beauty.",
        imageData: imageFile || undefined,
        pastryFormat: pastryFormat || "Single-tier Cake",
        theme,
        mode
      });
      setState({ isGenerating: false, result: result, error: null });
    } catch (err: any) {
      const errorMsg = (err.message || "").toLowerCase();
      if (errorMsg.includes("429") || errorMsg.includes("quota") || errorMsg.includes("limit")) {
         setIsFallbackMode(true);
         setState(prev => ({ ...prev, isGenerating: false, error: "The creative ethers are busy. Falling back to standard tier..." }));
         setTimeout(handleGenerate, 2500);
      } else {
        setState(prev => ({ ...prev, isGenerating: false, error: "The vision faded. Please attempt the manifestation again." }));
      }
    }
  };

  const toggleFavorite = (design: CakeDesign) => {
    const isFav = favorites.some(f => f.title === design.title && f.visualDescription === design.visualDescription);
    if (isFav) {
      setFavorites(favorites.filter(f => !(f.title === design.title && f.visualDescription === design.visualDescription)));
    } else {
      const toSave = { ...design, isShared: false, timestamp: Date.now() };
      setFavorites([toSave, ...favorites]);
    }
  };

  const shareDesign = (design: CakeDesign) => {
    try {
      const { imageUrl, ...shareableData } = design;
      const encoded = btoa(encodeURIComponent(JSON.stringify(shareableData)));
      const url = `${window.location.origin}${window.location.pathname}#${encoded}`;
      navigator.clipboard.writeText(url);
      setCopyStatus(design.id);
      setTimeout(() => setCopyStatus(null), 2000);
    } catch (e) {
      console.error("Failed to share", e);
    }
  };

  const isFavorited = useMemo(() => {
    if (!state.result) return false;
    return favorites.some(f => f.title === state.result?.title && f.visualDescription === state.result?.visualDescription);
  }, [state.result, favorites]);

  const safeStr = (val: any) => (typeof val === 'string' ? val : (val ? JSON.stringify(val) : ''));

  return (
