                    <button onClick={() => setImageFile(null)} className="absolute top-3 right-3 p-1.5 bg-black/40 text-white rounded-full backdrop-blur-md hover:bg-black/60 transition-colors shadow-lg"><X className="w-3 h-3" /></button>
