          <div className="lg:sticky lg:top-24 h-fit">
            {state.isGenerating ? (
              <div className="aspect-[4/5] bg-stone-100/30 rounded-[4rem] flex flex-col items-center justify-center p-12 text-center border border-stone-100 animate-pulse">
                <div className="relative w-24 h-24 mb-10">
                   <div className="absolute inset-0 border-2 border-stone-200 rounded-full animate-ping opacity-10" />
                   <div className="absolute inset-0 flex items-center justify-center">
                      <Palette className="w-12 h-12 text-stone-200" />
                   </div>
                </div>
                <p className="text-2xl serif italic text-stone-400 leading-relaxed max-w-xs">
                  "Manifesting the unnamable, touching the soul..."
                </p>
