                  {/* Reference Image Comparison View */}
                  {state.result.referenceImageUrl && (
                    <div className="absolute -left-12 top-12 w-32 h-32 rounded-3xl overflow-hidden shadow-2xl border-4 border-white rotate-[-8deg] hover:rotate-0 transition-all duration-500 z-10 group/ref">
                      <img src={state.result.referenceImageUrl} alt="Soul Baseline" className="w-full h-full object-cover opacity-80 group-hover/ref:opacity-100 transition-opacity" />
                      <div className="absolute inset-0 bg-stone-800/20 flex items-center justify-center opacity-0 group-hover/ref:opacity-100 transition-opacity">
                        <Eye className="w-6 h-6 text-white" />
                      </div>
                      <div className="absolute bottom-0 left-0 right-0 bg-white/90 py-1 text-[8px] uppercase tracking-tighter text-center font-bold text-stone-800">Soul Baseline</div>
                    </div>
                  )}

                  <div className="absolute -bottom-8 -right-8 flex gap-4">
                    <button onClick={() => shareDesign(state.result!)} className="p-6 bg-white text-stone-400 hover:text-stone-800 rounded-full shadow-2xl transition-all active:scale-95 group">
                      {copyStatus === state.result.id ? <Check className="w-6 h-6 text-green-500" /> : <Copy className="w-6 h-6 group-hover:scale-110" />}
                    </button>
                    <button onClick={() => toggleFavorite(state.result!)} className={`p-6 rounded-full shadow-2xl transition-all active:scale-95 ${isFavorited ? 'bg-red-500 text-white' : 'bg-white text-stone-400 hover:text-red-500'}`}>
                      <Heart className={`w-6 h-6 ${isFavorited ? 'fill-current' : ''}`} />
                    </button>
                  </div>
                </div>

                <div className="space-y-12 px-6">
                  <div className="space-y-6">
                    <div className="flex items-center gap-4 text-[10px] uppercase tracking-[0.4em] font-bold text-stone-300">
                      {state.result.mode === 'recreation' ? 'Étude de Maître' : 'Poésie Botanique'}
                      <div className="w-1.5 h-1.5 bg-stone-200 rounded-full" />
                      {state.result.pastryFormat || '1-Tier Cake'}
                    </div>
                    <h3 className="text-6xl font-light italic text-stone-800 leading-[0.85] tracking-tight max-w-lg">{safeStr(state.result.title)}</h3>
                    <p className="text-xl text-stone-500 font-light italic border-l-4 border-stone-100 pl-12 leading-relaxed max-w-xl">
                      {safeStr(state.result.visualDescription)}
                    </p>
                  </div>

                  <div className="grid grid-cols-4 gap-8 pb-12 border-b border-stone-100">
                    {state.result.colorRecipes.map((c, i) => (
                      <div key={i} className="space-y-4 group">
                        <div className="aspect-square rounded-[2rem] shadow-inner border border-stone-100 transition-all duration-700 group-hover:rounded-full group-hover:rotate-6" style={{ backgroundColor: safeStr(c.hex) }} />
                        <div className="text-[10px] uppercase font-bold text-stone-800 tracking-wider text-center md:text-left">{safeStr(c.name)}</div>
                      </div>
                    ))}
                  </div>

                  <div className="bg-white p-14 rounded-[4rem] border border-stone-100 space-y-14 shadow-sm relative overflow-hidden ring-1 ring-stone-50">
                    <div className="space-y-10">
                      <div className="flex items-center gap-5">
                        <Droplets className="w-5 h-5 text-stone-200" />
                        <h4 className="text-xs uppercase tracking-[0.3em] font-bold text-stone-800">Mixing Directives</h4>
                      </div>
                      <div className="space-y-8">
                        {state.result.colorRecipes.map((c, i) => (
                          <div key={i} className="flex gap-8 group items-center">
                            <div className="w-12 h-12 rounded-full flex-shrink-0 border-4 border-white shadow-xl ring-1 ring-stone-50 group-hover:scale-110 transition-transform" style={{ backgroundColor: safeStr(c.hex) }} />
                            <div>
                              <div className="text-[10px] uppercase font-bold text-stone-700 tracking-[0.2em] mb-1">{safeStr(c.name)}</div>
                              <p className="text-sm text-stone-400 font-light italic leading-snug">{safeStr(c.recipe)}</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                    <div className="pt-12 border-t border-stone-50">
                      <div className="flex items-center gap-5 mb-6">
                        <Brush className="w-5 h-5 text-stone-200" />
                        <h4 className="text-xs uppercase tracking-[0.3em] font-bold text-stone-800">Gestural Execution</h4>
                      </div>
                      <p className="text-sm text-stone-500 font-light leading-relaxed italic border-l-2 border-stone-50 pl-10 max-w-md">{safeStr(state.result.technique)}</p>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="aspect-[4/5] bg-stone-50/30 rounded-[4rem] border-2 border-dashed border-stone-100 flex flex-col items-center justify-center p-24 text-center text-stone-300 transition-all duration-1000 hover:bg-stone-50/50">
                <Feather className="w-16 h-16 mb-8 opacity-10 animate-pulse" />
