            </header>

            <div className="bg-white p-8 rounded-[3rem] border border-stone-100 shadow-sm space-y-8 relative overflow-hidden">
              <div className="flex p-1 bg-stone-50 rounded-2xl">
                <button 
                  onClick={() => setMode('poetic')}
                  className={`flex-1 flex flex-col items-center justify-center py-4 rounded-xl transition-all ${mode === 'poetic' ? 'bg-white text-stone-800 shadow-sm' : 'text-stone-400 opacity-60'}`}
                >
                  <Feather className="w-4 h-4 mb-1" />
                  <span className="text-[9px] uppercase tracking-widest font-bold">Poésie Botanique</span>
                </button>
                <button 
                  onClick={() => setMode('recreation')}
                  className={`flex-1 flex flex-col items-center justify-center py-4 rounded-xl transition-all ${mode === 'recreation' ? 'bg-white text-stone-800 shadow-sm' : 'text-stone-400 opacity-60'}`}
                >
                  <Brush className="w-4 h-4 mb-1" />
                  <span className="text-[9px] uppercase tracking-widest font-bold">Étude de Maître</span>
