              </div>

              <div className="grid md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest font-bold text-stone-400">Pastry Vessel</label>
                  <input 
                    type="text" 
                    value={pastryFormat}
