              </div>

              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-stone-400">
                  {mode === 'poetic' ? "The Whimsical Heart" : "The Subject of Devotion"}
                </label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder={mode === 'poetic' 
                    ? "A half-forgotten dream of a winter garden... something abstract and unnamable..." 
                    : "Describe the essence or subject you uploaded..."}
                  className="w-full h-32 bg-stone-50 border-none rounded-2xl p-4 focus:ring-1 focus:ring-stone-200 outline-none text-stone-700 font-light resize-none text-xs leading-relaxed shadow-inner"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-stone-400">Soul Baseline (Reference)</label>
                {imageFile ? (
                  <div className="relative aspect-video rounded-[2rem] overflow-hidden shadow-inner border border-stone-100">
                    <img src={imageFile} alt="Reference" className="w-full h-full object-cover grayscale-[10%]" />
                    <button onClick={() => setImageFile(null)} className="absolute top-3 right-3 p-1.5 bg-black/40 text-white rounded-full backdrop-blur-md hover:bg-black/60 transition-colors shadow-lg"><X className="w-3 h-3" /></button>
                  </div>
                ) : (
                  <label className="flex flex-col items-center justify-center w-full aspect-video border-2 border-dashed border-stone-100 rounded-[2.5rem] cursor-pointer hover:bg-stone-50 transition-all group">
                    <Camera className="w-6 h-6 text-stone-200 mb-3 group-hover:text-stone-400 transition-colors" />
                    <p className="text-[10px] text-stone-400 uppercase tracking-widest font-bold">Anchor the design</p>
                    <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                  </label>
                )}
              </div>

              <button
                disabled={state.isGenerating || (!prompt && !imageFile)}
                onClick={handleGenerate}
                className="w-full py-5 bg-stone-800 text-white rounded-[2rem] hover:bg-stone-700 transition-all font-medium flex items-center justify-center gap-3 disabled:opacity-50 group shadow-xl"
              >
                {state.isGenerating ? <><Loader2 className="w-5 h-5 animate-spin" /> Composing your poem...</> : <><Sparkles className="w-5 h-5 group-hover:rotate-12 transition-transform" /> Manifest Art</>}
              </button>

              <button onClick={() => setShowLogic(true)} className="w-full text-[10px] uppercase font-bold text-stone-300 hover:text-stone-800 transition-colors tracking-widest">Our Artistic Vocation</button>
            </div>
          </div>

          <div className="lg:sticky lg:top-24 h-fit">
            {state.isGenerating ? (
              <div className="aspect-[4/5] bg-stone-100/30 rounded-[4rem] flex flex-col items-center justify-center p-12 text-center border border-stone-100 animate-pulse">
                <div className="relative w-24 h-24 mb-10">
                   <div className="absolute inset-0 border-2 border-stone-200 rounded-full animate-ping opacity-10" />
                   <div className="absolute inset-0 flex items-center justify-center">
                      <Palette className="w-12 h-12 text-stone-200" />
                   </div>
                </div>
                <p className="text-2xl serif italic text-stone-400 leading-relaxed max-w-xs">
                  "Manifesting the unnamable, touching the soul..."
                </p>
              </div>
            ) : state.result ? (
              <div className="space-y-16 animate-in fade-in slide-in-from-bottom-12 duration-1000">
                <div className="relative space-y-4">
                  <div className="aspect-[4/5] rounded-[4rem] overflow-hidden shadow-2xl border border-stone-100 bg-white group ring-1 ring-stone-50">
                    {state.result.imageUrl ? (
                      <img src={state.result.imageUrl} alt="Manifested Design" className="w-full h-full object-cover grayscale-[5%] hover:grayscale-0 transition-all duration-1000 group-hover:scale-105" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center bg-stone-50 italic text-stone-300">Design Vision Transmitted</div>
                    )}
                  </div>

                  {state.result.referenceImageUrl && (
                    <div className="absolute -left-12 top-12 w-32 h-32 rounded-3xl overflow-hidden shadow-2xl border-4 border-white rotate-[-8deg] hover:rotate-0 transition-all duration-500 z-10 group/ref">
                      <img src={state.result.referenceImageUrl} alt="Soul Baseline" className="w-full h-full object-cover opacity-80 group-hover/ref:opacity-100 transition-opacity" />
                      <div className="absolute inset-0 bg-stone-800/20 flex items-center justify-center opacity-0 group-hover/ref:opacity-100 transition-opacity">
                        <Eye className="w-6 h-6 text-white" />
                      </div>
                      <div className="absolute bottom-0 left-0 right-0 bg-white/90 py-1 text-[8px] uppercase tracking-tighter text-center font-bold text-stone-800">Soul Baseline</div>
                    </div>
                  )}

                  <div className="absolute -bottom-10 -right-8 flex gap-4">
                    <button 
                      onClick={() => state.result?.imageUrl && downloadImage(state.result.imageUrl, state.result.title)} 
                      title="Download Manifestation"
                      className="p-6 bg-white text-stone-400 hover:text-stone-800 rounded-full shadow-2xl transition-all active:scale-95 group"
                    >
                      <Download className="w-6 h-6 group-hover:translate-y-0.5 transition-transform" />
                    </button>
                    <button 
                      onClick={() => shareDesign(state.result!)} 
                      title="Share Manifestation"
                      className="p-6 bg-white text-stone-400 hover:text-stone-800 rounded-full shadow-2xl transition-all active:scale-95 group"
                    >
                      {copyStatus === state.result.id ? <Check className="w-6 h-6 text-green-500" /> : <Copy className="w-6 h-6 group-hover:scale-110" />}
                    </button>
                    <button 
                      onClick={() => toggleFavorite(state.result!)} 
                      title={isFavorited ? "Remove from Gallery" : "Save to Gallery"}
                      className={`p-6 rounded-full shadow-2xl transition-all active:scale-95 ${isFavorited ? 'bg-red-500 text-white shadow-red-200' : 'bg-white text-stone-400 hover:text-red-500'}`}
                    >
                      <Heart className={`w-6 h-6 ${isFavorited ? 'fill-current' : ''}`} />
                    </button>
                  </div>
                </div>

                <div className="space-y-12 px-6">
                  <div className="space-y-6">
                    <div className="flex items-center gap-4 text-[10px] uppercase tracking-[0.4em] font-bold text-stone-300">
                      {state.result.mode === 'recreation' ? 'Étude de Maître' : 'Poésie Botanique'}
                      <div className="w-1.5 h-1.5 bg-stone-200 rounded-full" />
                      {state.result.pastryFormat || '1-Tier Cake'}
                    </div>
                    <h3 className="text-6xl font-light italic text-stone-800 leading-[0.85] tracking-tight max-w-lg">{safeStr(state.result.title)}</h3>
                    <p className="text-xl text-stone-500 font-light italic border-l-4 border-stone-100 pl-12 leading-relaxed max-w-xl">
                      {safeStr(state.result.visualDescription)}
                    </p>
                  </div>

                  <div className="grid grid-cols-4 gap-8 pb-12 border-b border-stone-100">
                    {state.result.colorRecipes.map((c, i) => (
                      <div key={i} className="space-y-4 group">
                        <div className="aspect-square rounded-[2rem] shadow-inner border border-stone-100 transition-all duration-700 group-hover:rounded-full group-hover:rotate-6" style={{ backgroundColor: safeStr(c.hex) }} />
                        <div className="text-[10px] uppercase font-bold text-stone-800 tracking-wider text-center md:text-left">{safeStr(c.name)}</div>
                      </div>
                    ))}
                  </div>

                  <div className="bg-white p-14 rounded-[4rem] border border-stone-100 space-y-14 shadow-sm relative overflow-hidden ring-1 ring-stone-50">
                    <div className="space-y-10">
                      <div className="flex items-center gap-5">
                        <Droplets className="w-5 h-5 text-stone-200" />
                        <h4 className="text-xs uppercase tracking-[0.3em] font-bold text-stone-800">Mixing Directives</h4>
                      </div>
                      <div className="space-y-8">
                        {state.result.colorRecipes.map((c, i) => (
                          <div key={i} className="flex gap-8 group items-center">
                            <div className="w-12 h-12 rounded-full flex-shrink-0 border-4 border-white shadow-xl ring-1 ring-stone-50 group-hover:scale-110 transition-transform" style={{ backgroundColor: safeStr(c.hex) }} />
                            <div>
                              <div className="text-[10px] uppercase font-bold text-stone-700 tracking-[0.2em] mb-1">{safeStr(c.name)}</div>
                              <p className="text-sm text-stone-400 font-light italic leading-snug">{safeStr(c.recipe)}</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                    <div className="pt-12 border-t border-stone-50">
                      <div className="flex items-center gap-5 mb-6">
                        <Brush className="w-5 h-5 text-stone-200" />
                        <h4 className="text-xs uppercase tracking-[0.3em] font-bold text-stone-800">Gestural Execution</h4>
                      </div>
                      <p className="text-sm text-stone-500 font-light leading-relaxed italic border-l-2 border-stone-50 pl-10 max-w-md">{safeStr(state.result.technique)}</p>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="aspect-[4/5] bg-stone-50/30 rounded-[4rem] border-2 border-dashed border-stone-100 flex flex-col items-center justify-center p-24 text-center text-stone-300 transition-all duration-1000 hover:bg-stone-50/50">
                <Feather className="w-16 h-16 mb-8 opacity-10 animate-pulse" />
                <p className="text-sm font-light italic leading-relaxed max-w-xs opacity-60">
                  Compose your whimsical poem to reveal a vision that touches the soul.
                </p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Palette, Feather, Sparkles, Image as ImageIcon, Loader2, Camera, ArrowRight, X, AlertCircle, Heart, Trash2, BookOpen, Info, Droplets, Share2, Check, Copy, Globe, Layers, Layout, Brush, HeartHandshake, Eye, Download, FileText } from 'lucide-react';
import { generateCakeDesign } from './services/geminiService';
import { AppState, CakeDesign, StudioMode } from './types';
import { jsPDF } from 'jspdf';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [pastryFormat, setPastryFormat] = useState('');
  const [theme, setTheme] = useState('');
  const [mode, setMode] = useState<StudioMode>('poetic');
  const [imageFile, setImageFile] = useState<string | null>(null);
  const [state, setState] = useState<AppState>({
    isGenerating: false,
    result: null,
    error: null
  });
  const [favorites, setFavorites] = useState<CakeDesign[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);
  const [showLogic, setShowLogic] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [isFallbackMode, setIsFallbackMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('qp_favorites_v2');
    if (saved) {
      try {
        setFavorites(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load favorites", e);
      }
    }

    const handleSharedLink = () => {
      const hash = window.location.hash;
      if (hash && hash.length > 1) {
        try {
          const encodedData = hash.substring(1);
          const decodedData = JSON.parse(decodeURIComponent(atob(encodedData)));
          if (decodedData && decodedData.title) {
            const sharedDesign = { ...decodedData, isShared: true };
            setState(prev => ({ ...prev, result: sharedDesign }));
            setShowFavorites(true);
          }
        } catch (e) {
          console.error("Failed to decode shared design", e);
        }
      }
    };

    handleSharedLink();
    window.addEventListener('hashchange', handleSharedLink);
    return () => window.removeEventListener('hashchange', handleSharedLink);
  }, []);

  useEffect(() => {
    localStorage.setItem('qp_favorites_v2', JSON.stringify(favorites));
  }, [favorites]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    setIsFallbackMode(false);

    try {
      const result = await generateCakeDesign({
        prompt: prompt || "A feeling of unnamable peace.",
        imageData: imageFile || undefined,
        pastryFormat: pastryFormat || "Single-tier Cake",
        theme,
        mode
      });

      const finalResult = { 
        ...result, 
        referenceImageUrl: imageFile || undefined 
      };

      setState({ isGenerating: false, result: finalResult, error: null });
    } catch (err: any) {
      const errorMsg = (err.message || "").toLowerCase();
      if (errorMsg.includes("429") || errorMsg.includes("quota") || errorMsg.includes("limit")) {
         setIsFallbackMode(true);
         setState(prev => ({ ...prev, isGenerating: false, error: "The creative ethers are crowded. Manifesting in standard tier..." }));
         setTimeout(handleGenerate, 2500);
      } else {
        setState(prev => ({ ...prev, isGenerating: false, error: "The mist settled unexpectedly. Please attempt the manifest again." }));
      }
    }
  };

  const toggleFavorite = (design: CakeDesign) => {
    const isFav = favorites.some(f => f.title === design.title && f.visualDescription === design.visualDescription);
    if (isFav) {
      setFavorites(favorites.filter(f => !(f.title === design.title && f.visualDescription === design.visualDescription)));
    } else {
      const toSave = { ...design, isShared: false, timestamp: Date.now() };
      setFavorites([toSave, ...favorites]);
    }
  };

  const shareDesign = (design: CakeDesign) => {
    try {
      const { imageUrl, ...shareableData } = design;
      const encoded = btoa(encodeURIComponent(JSON.stringify(shareableData)));
      const url = `${window.location.origin}${window.location.pathname}#${encoded}`;
      navigator.clipboard.writeText(url);
      setCopyStatus(design.id);
      setTimeout(() => setCopyStatus(null), 2000);
    } catch (e) {
      console.error("Failed to share", e);
    }
  };

  const downloadImage = (base64Data: string, filename: string) => {
    const link = document.createElement('a');
    link.href = base64Data;
    link.download = `${filename.replace(/\s+/g, '_').toLowerCase()}_manifest.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const downloadPdf = async (design: CakeDesign) => {
    const doc = new jsPDF({
      orientation: 'p',
      unit: 'mm',
      format: 'a4'
    });

    const title = safeStr(design.title);
    const fileName = `${title.replace(/\s+/g, '_').toLowerCase()}_manifest.pdf`;

    // 1. Header
    doc.setFont('times', 'italic');
    doc.setFontSize(10);
    doc.setTextColor(150, 150, 150);
    doc.text('Quille en Poème - Studio de Pâtisserie Botanique', 105, 15, { align: 'center' });

    // 2. Main Title
    doc.setFont('times', 'bolditalic');
    doc.setFontSize(28);
    doc.setTextColor(45, 45, 45);
    doc.text(title, 105, 35, { align: 'center' });

    // 3. The Image
    if (design.imageUrl) {
      const imgWidth = 140;
      const imgHeight = 140;
      const x = (210 - imgWidth) / 2;
      doc.addImage(design.imageUrl, 'PNG', x, 45, imgWidth, imgHeight);
    }

    // 4. Description
    doc.setFont('times', 'italic');
    doc.setFontSize(14);
    doc.setTextColor(100, 100, 100);
    const splitDesc = doc.splitTextToSize(safeStr(design.visualDescription), 170);
    doc.text(splitDesc, 105, 195, { align: 'center' });

    // 5. Technique & Details
    doc.addPage();
    doc.setFont('times', 'bold');
    doc.setFontSize(18);
    doc.setTextColor(45, 45, 45);
    doc.text('Le Guide de Manifestation', 20, 30);

    doc.setFontSize(10);
    doc.setFont('times', 'normal');
    doc.text(`Format: ${design.pastryFormat || 'N/A'}`, 20, 40);
    doc.text(`Occasion: ${design.theme || 'N/A'}`, 20, 45);

    doc.setFont('times', 'bold');
    doc.text('Geste Technique (Spatule):', 20, 60);
    doc.setFont('times', 'italic');
    const splitTech = doc.splitTextToSize(safeStr(design.technique), 170);
    doc.text(splitTech, 20, 65);

    // 6. Color Palette
    doc.setFont('times', 'bold');
    doc.setFontSize(14);
    doc.text('La Palette de l\'Âme', 20, 95);

    let startY = 105;
    design.colorRecipes.forEach((color, index) => {
      // Color block
      doc.setFillColor(color.hex);
      doc.rect(20, startY, 15, 15, 'F');
      doc.setDrawColor(230, 230, 230);
      doc.rect(20, startY, 15, 15, 'S');

      // Color name & recipe
      doc.setFont('times', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(45, 45, 45);
      doc.text(safeStr(color.name).toUpperCase(), 40, startY + 6);

      doc.setFont('times', 'italic');
      doc.setTextColor(120, 120, 120);
      const splitRecipe = doc.splitTextToSize(`Recette: ${safeStr(color.recipe)}`, 130);
      doc.text(splitRecipe, 40, startY + 11);

      startY += 25;
    });

    // 7. Footer on second page
    doc.setFont('times', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(180, 180, 180);
    doc.text('Transformez le sucre en poésie. Respectez la pâtisserie comme un art de l\'âme.', 105, 285, { align: 'center' });

    doc.save(fileName);
  };

  const isFavorited = useMemo(() => {
    if (!state.result) return false;
    return favorites.some(f => f.title === state.result?.title && f.visualDescription === state.result?.visualDescription);
  }, [state.result, favorites]);

  const safeStr = (val: any) => (typeof val === 'string' ? val : (val ? JSON.stringify(val) : ''));

  return (
    <div className="min-h-screen pb-20 relative bg-[#faf9f6]">
      <nav className="sticky top-0 z-50 ethereal-blur border-b border-stone-100 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-stone-800 rounded-full flex items-center justify-center">
            <span className="text-white text-xs font-serif italic">QP</span>
          </div>
          <h1 className="text-xl tracking-widest uppercase font-light text-stone-800">Quille en Poème</h1>
        </div>
        <div className="flex items-center gap-4 text-xs tracking-widest uppercase text-stone-500 font-medium">
          <button 
            onClick={() => setShowFavorites(!showFavorites)} 
            className="px-4 py-2 bg-white rounded-full border border-stone-100 shadow-sm hover:shadow-md transition-all flex items-center gap-2 group"
          >
            <BookOpen className="w-4 h-4 text-stone-400 group-hover:text-stone-800" />
            Galerie ({favorites.length})
          </button>
        </div>
      </nav>

      {/* Philosophy Panel */}
      <div className={`fixed inset-y-0 left-0 w-full md:w-80 bg-white z-[60] shadow-2xl transition-transform duration-500 ease-out border-r border-stone-100 flex flex-col ${showLogic ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 border-b border-stone-100 flex justify-between items-center">
          <h3 className="text-sm tracking-widest uppercase font-bold text-stone-800">L'Esprit du Design</h3>
          <button onClick={() => setShowLogic(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors"><X className="w-4 h-4" /></button>
        </div>
        <div className="p-6 space-y-8 overflow-y-auto">
          <div className="space-y-4 text-stone-500 text-[11px] font-light leading-relaxed">
            <div className="p-4 bg-stone-50 rounded-2xl border border-stone-100 space-y-3 mb-4">
               <HeartHandshake className="w-5 h-5 text-stone-400" />
               <p className="text-[11px] text-stone-600 italic leading-relaxed">
                 "Our mission is to manifest the unnamable, touching the soul of the consumer through edible poetry."
               </p>
            </div>
            <h4 className="text-xs uppercase tracking-widest font-bold text-stone-400">Color Alchemy</h4>
            <div className="space-y-3">
              <p><strong>Dusty/Muted:</strong> Base + Brown + White.</p>
              <p><strong>Vintage Greens:</strong> Green + Orange + White.</p>
              <p><strong>Twilight Purples:</strong> Blue + Red + Black + White.</p>
              <p><strong>Champagne:</strong> White + Yellow (dot) + Brown (dot).</p>
            </div>
          </div>
        </div>
      </div>

      {/* Gallery Panel */}
      <div className={`fixed inset-y-0 right-0 w-full md:w-96 bg-[#faf9f6] z-[60] shadow-2xl transition-transform duration-500 ease-out border-l border-stone-100 flex flex-col ${showFavorites ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-6 bg-white border-b border-stone-100 flex justify-between items-center">
          <div className="space-y-1">
            <h3 className="text-xl tracking-widest uppercase font-light text-stone-800">Museum Gallery</h3>
            <p className="text-[10px] text-stone-400 uppercase tracking-widest">Saved Inspirations</p>
          </div>
          <button onClick={() => setShowFavorites(false)} className="p-2 hover:bg-stone-50 rounded-full transition-colors"><X className="w-5 h-5 text-stone-400" /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {favorites.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center opacity-40">
              <Globe className="w-10 h-10 text-stone-300 stroke-1 mb-4" />
