import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign, StudioMode } from "../types";

export interface GenerateParams {
  prompt: string;
  imageData?: string;
  pastryFormat?: string;
  theme?: string;
  mode: StudioMode;
}

export const generateCakeDesign = async (params: GenerateParams): Promise<CakeDesign> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any[] = [{ 
    text: `
      PLEASE GENERATE A VISUAL MANIFESTATION (IMAGE) AND DESIGN DATA FOR THE FOLLOWING CREATION:

      STUDIO MODE: ${params.mode === 'recreation' ? 'Étude de Maître (Recreation)' : 'Poésie Botanique'}
      PASTRY FORMAT: ${params.pastryFormat || 'Single-tier Cake'}
      THEME/OCCASION: ${params.theme || 'Artistic expression'}
      POEM/PROMPT/SUBJECT: ${params.prompt}

      Remember to provide a visual image part representing the finished design, and a text part containing the JSON design data.
    ` 
  }];

  if (params.imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: params.imageData.split(',')[1]
      }
    });
  }

  try {
    return await callModel(ai, 'gemini-3-pro-image-preview', contents, params.mode);
  } catch (error: any) {
    const errorMsg = (error.message || "").toLowerCase();
    console.warn("Primary model failed or quota exceeded. Falling back to Flash model...", errorMsg);

    // Create fresh instance for fallback
    const fallbackAi = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      return await callModel(fallbackAi, 'gemini-2.5-flash-image', contents, params.mode);
    } catch (fallbackError) {
      console.error("Fallback model manifestation failed.", fallbackError);
      throw fallbackError;
    }
  }
};

async function callModel(ai: any, modelName: string, contents: any[], mode: StudioMode): Promise<CakeDesign> {
  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: contents },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: "1K"
      },
    },
  });

  let cakeData: any = {};
  let imageUrl: string | undefined;

  // Extract text and find JSON block
  const fullText = response.text || "";
  try {
    const jsonMatch = fullText.match(/\{[\s\S]*\}/);
    const jsonStr = jsonMatch ? jsonMatch[0] : fullText;
    cakeData = JSON.parse(jsonStr.replace(/```json|```/g, '').trim());
  } catch (e) {
    console.error("Design parsing error, applying fallback structure.", e);
    cakeData = {
      title: "L'Essence du Poème",
      visualDescription: fullText.split('\n')[0].substring(0, 250),
      technique: "Impressionist spatula strokes."
    };
  }

  // Extract the generated image part
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }

  return {
    id: Math.random().toString(36).substring(2, 9),
    timestamp: Date.now(),
    title: String(cakeData.title || "Untitled Manifestation"),
    visualDescription: String(cakeData.visualDescription || "A soulful vision caught in the creative ether."),
    technique: String(cakeData.technique || "Soft palette-knife blending."),
    colorRecipes: Array.isArray(cakeData.colorRecipes) ? cakeData.colorRecipes.map((c: any) => ({
      name: String(c.name || 'Artisan Mist'),
      hex: String(c.hex || '#ffffff'),
      recipe: String(c.recipe || 'Blend with ample White.')
    })) : [],
    imageUrl: imageUrl,
    mode: mode
  };
}

import React, { useState, useEffect, useMemo } from 'react';
import { Palette, Feather, Sparkles, Image as ImageIcon, Loader2, Camera, ArrowRight, X, AlertCircle, Heart, Trash2, BookOpen, Info, Droplets, Share2, Check, Copy, Globe, Layers, Layout, Brush, HeartHandshake, Eye, Download, FileText, Key } from 'lucide-react';
import { generateCakeDesign } from './services/geminiService';
import { AppState, CakeDesign, StudioMode } from './types';
import { jsPDF } from 'jspdf';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [pastryFormat, setPastryFormat] = useState('');
  const [theme, setTheme] = useState('');
  const [mode, setMode] = useState<StudioMode>('poetic');
  const [imageFile, setImageFile] = useState<string | null>(null);
  const [state, setState] = useState<AppState>({
    isGenerating: false,
    result: null,
    error: null
  });
  const [favorites, setFavorites] = useState<CakeDesign[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);
  const [showLogic, setShowLogic] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [isFallbackMode, setIsFallbackMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('qp_favorites_v2');
    if (saved) {
      try {
        setFavorites(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load favorites", e);
      }
    }

    const handleSharedLink = () => {
      const hash = window.location.hash;
      if (hash && hash.length > 1) {
        try {
          const encodedData = hash.substring(1);
          const decodedData = JSON.parse(decodeURIComponent(atob(encodedData)));
          if (decodedData && decodedData.title) {
            const sharedDesign = { ...decodedData, isShared: true };
            setState(prev => ({ ...prev, result: sharedDesign }));
            setShowFavorites(true);
          }
        } catch (e) {
          console.error("Failed to decode shared design", e);
        }
      }
    };

    handleSharedLink();
    window.addEventListener('hashchange', handleSharedLink);
    return () => window.removeEventListener('hashchange', handleSharedLink);
  }, []);

  useEffect(() => {
    localStorage.setItem('qp_favorites_v2', JSON.stringify(favorites));
  }, [favorites]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const ensureApiKey = async () => {
    const aistudio = (window as any).aistudio;
    if (aistudio && typeof aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await aistudio.openSelectKey();
      }
    }
    return true;
  };

  const handleGenerate = async () => {
    if (!prompt && !imageFile) return;

    // Mandatory key check for gemini-3-pro-image-preview
    await ensureApiKey();

    setState(prev => ({ ...prev, isGenerating: true, error: null }));
    setIsFallbackMode(false);

    try {
      const result = await generateCakeDesign({
        prompt: prompt || "A feeling of unnamable peace and botanical beauty.",
        imageData: imageFile || undefined,
        pastryFormat: pastryFormat || "Single-tier Cake",
        theme,
        mode
      });

      const finalResult = { 
        ...result, 
        referenceImageUrl: imageFile || undefined 
      };

      setState({ isGenerating: false, result: finalResult, error: null });
    } catch (err: any) {
      const errorMsg = (err.message || "").toLowerCase();
      if (errorMsg.includes("429") || errorMsg.includes("quota") || errorMsg.includes("limit")) {
         setIsFallbackMode(true);
         setState(prev => ({ ...prev, isGenerating: false, error: "The creative ethers are crowded. Falling back to standard tier manifestation..." }));
         setTimeout(handleGenerate, 2000);
      } else if (errorMsg.includes("requested entity was not found")) {
        // Reset key selection if model not found error
        const aistudio = (window as any).aistudio;
        if (aistudio && typeof aistudio.openSelectKey === 'function') {
          await aistudio.openSelectKey();
        }
        setState(prev => ({ ...prev, isGenerating: false, error: "Artistic permissions required. Please ensure a valid API key is selected." }));
      } else {
        setState(prev => ({ ...prev, isGenerating: false, error: "The vision faded unexpectedly. Please attempt the manifest again." }));
      }
    }
  };

  const toggleFavorite = (design: CakeDesign) => {
    const isFav = favorites.some(f => f.title === design.title && f.visualDescription === design.visualDescription);
    if (isFav) {
      setFavorites(favorites.filter(f => !(f.title === design.title && f.visualDescription === design.visualDescription)));
    } else {
      const toSave = { ...design, isShared: false, timestamp: Date.now() };
      setFavorites([toSave, ...favorites]);
    }
  };

  const shareDesign = (design: CakeDesign) => {
    try {
      const { imageUrl, referenceImageUrl, ...shareableData } = design;
      const encoded = btoa(encodeURIComponent(JSON.stringify(shareableData)));
      const url = `${window.location.origin}${window.location.pathname}#${encoded}`;
      navigator.clipboard.writeText(url);
      setCopyStatus(design.id);
      setTimeout(() => setCopyStatus(null), 2000);
    } catch (e) {
      console.error("Failed to share", e);
    }
  };

  const downloadImage = (base64Data: string, filename: string) => {
    const link = document.createElement('a');
    link.href = base64Data;
    link.download = `${filename.replace(/\s+/g, '_').toLowerCase()}_manifest.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const downloadPdf = async (design: CakeDesign) => {
    const doc = new jsPDF({
      orientation: 'p',
      unit: 'mm',
      format: 'a4'
    });

    const title = safeStr(design.title);
    const fileName = `${title.replace(/\s+/g, '_').toLowerCase()}_guide.pdf`;

    // Page 1: Design Manifestation
    doc.setFont('times', 'italic');
    doc.setFontSize(10);
    doc.setTextColor(180, 180, 180);
    doc.text('Quille en Poème - Studio de Pâtisserie Impressionniste', 105, 15, { align: 'center' });

    doc.setFont('times', 'bolditalic');
    doc.setFontSize(32);
    doc.setTextColor(45, 45, 45);
    doc.text(title, 105, 35, { align: 'center' });

    if (design.imageUrl) {
      const imgWidth = 150;
      const imgHeight = 150;
      const x = (210 - imgWidth) / 2;
      doc.addImage(design.imageUrl, 'PNG', x, 45, imgWidth, imgHeight);
    }

    doc.setFont('times', 'italic');
    doc.setFontSize(14);
    doc.setTextColor(100, 100, 100);
    const splitDesc = doc.splitTextToSize(safeStr(design.visualDescription), 170);
    doc.text(splitDesc, 105, 205, { align: 'center' });

    // Page 2: Mixing & Technique
    doc.addPage();
    doc.setFont('times', 'bold');
    doc.setFontSize(22);
    doc.setTextColor(45, 45, 45);
    doc.text('Le Guide de Manifestation', 20, 30);

    doc.setFontSize(11);
    doc.setFont('times', 'normal');
    doc.setTextColor(120, 120, 120);
    doc.text(`Vessel: ${design.pastryFormat || 'Patisserie Art'}`, 20, 42);
    doc.text(`Aura: ${design.theme || 'Artistic Devotion'}`, 20, 48);

    doc.setFont('times', 'bold');
    doc.setFontSize(14);
    doc.setTextColor(45, 45, 45);
    doc.text('L\'Alchimie des Couleurs', 20, 65);

    let startY = 75;
    design.colorRecipes.forEach((color, index) => {
      doc.setFillColor(color.hex);
      doc.rect(20, startY, 18, 18, 'F');
      doc.setDrawColor(240, 240, 240);
      doc.rect(20, startY, 18, 18, 'S');

      doc.setFont('times', 'bold');
      doc.setFontSize(11);
      doc.setTextColor(45, 45, 45);
      doc.text(safeStr(color.name).toUpperCase(), 45, startY + 7);

      doc.setFont('times', 'italic');
      doc.setFontSize(10);
      doc.setTextColor(140, 140, 140);
      const splitRecipe = doc.splitTextToSize(`Directives: ${safeStr(color.recipe)}`, 135);
      doc.text(splitRecipe, 45, startY + 13);

      startY += 30;
    });

    doc.setFont('times', 'bold');
    doc.setFontSize(14);
    doc.setTextColor(45, 45, 45);
    doc.text('Gestuelle Technique', 20, startY + 5);

    doc.setFont('times', 'italic');
    doc.setFontSize(11);
    doc.setTextColor(100, 100, 100);
    const splitTech = doc.splitTextToSize(safeStr(design.technique), 170);
    doc.text(splitTech, 20, startY + 15);

    doc.setFont('times', 'normal');
    doc.setFontSize(9);
    doc.setTextColor(200, 200, 200);
    doc.text('Quille en Poème: La poésie n\'est pas un luxe, c\'est un souffle.', 105, 285, { align: 'center' });

    doc.save(fileName);
  };

  const isFavorited = useMemo(() => {
    if (!state.result) return false;
