import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign, StudioMode } from "../types";

export interface GenerateParams {
  prompt: string;
  imageData?: string;
  pastryFormat?: string;
  theme?: string;
  mode: StudioMode;
}

export const generateCakeDesign = async (params: GenerateParams): Promise<CakeDesign> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any[] = [{ 
    text: `
      STUDIO MISSION: Manifest the following "poem" into a visual pastry masterpiece.

      STUDIO MODE: ${params.mode === 'recreation' ? 'Étude de Maître' : 'Poésie Botanique'}
      PASTRY FORMAT: ${params.pastryFormat || 'Single-tier Cake'}
      THEME/OCCASION: ${params.theme || 'Artistic Devotion'}
      THE POEM/PROMPT: "${params.prompt}"

      MANDATORY: 
      1. Provide a beautiful IMAGE of the cake.
      2. Provide a JSON block containing "title", "visualDescription", "technique", and "colorRecipes" with Peotraco mix ratios.
    ` 
  }];

  if (params.imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: params.imageData.split(',')[1]
      }
    });
  }

  try {
    return await callModel(ai, 'gemini-3-pro-image-preview', contents, params.mode);
  } catch (error: any) {
    const errorMsg = (error.message || "").toLowerCase();
    console.warn("Primary model failed. Attempting fallback manifestation...", errorMsg);

    const fallbackAi = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      return await callModel(fallbackAi, 'gemini-2.5-flash-image', contents, params.mode);
    } catch (fallbackError) {
      console.error("Critical: All manifestations failed.", fallbackError);
      throw fallbackError;
    }
  }
};

async function callModel(ai: any, modelName: string, contents: any[], mode: StudioMode): Promise<CakeDesign> {
  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: contents },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: "1K"
      },
    },
  });

  let cakeData: any = {};
  let imageUrl: string | undefined;

  // Extraction logic for the JSON block
  const fullText = response.text || "";
  try {
    // Look for JSON block with improved regex
    const jsonMatch = fullText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      let rawJson = jsonMatch[0];
      // Clean up markdown markers and surrounding whitespace
      rawJson = rawJson.replace(/```json/g, '').replace(/```/g, '').trim();
      cakeData = JSON.parse(rawJson);
    } else {
      throw new Error("No JSON block found in response.");
    }
  } catch (e) {
    console.error("JSON extraction failed. Attempting partial recovery.", e);
    // Fallback data if JSON parsing is completely broken
    cakeData = {
      title: "L'Essence Perdue",
      visualDescription: fullText.length > 50 ? fullText.substring(0, 300) : "A vision that briefly touched the ether but could not be fully captured.",
      technique: "Apply soft spatula strokes to create a sense of misty memory.",
      colorRecipes: []
    };
  }

  // Extraction logic for the Image part
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }

  return {
    id: Math.random().toString(36).substring(2, 9),
    timestamp: Date.now(),
    title: cakeData.title || "Untitled Poem",
    visualDescription: cakeData.visualDescription || "A soulful vision caught in the creative ether.",
    technique: cakeData.technique || "Soft palette-knife blending.",
    colorRecipes: Array.isArray(cakeData.colorRecipes) ? cakeData.colorRecipes : [],
    imageUrl: imageUrl,
    mode: mode
  };
}

