import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign, StudioMode } from "../types";

export interface GenerateParams {
  prompt: string;
  imageData?: string;
  pastryFormat?: string;
  theme?: string;
  mode: StudioMode;
}

export const generateCakeDesign = async (params: GenerateParams): Promise<CakeDesign> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any[] = [{ 
    text: `
      COMMAND: MANIFEST THE FOLLOWING POEM INTO A PHYSICAL PASTRY DESIGN.

      STUDIO MODE: ${params.mode === 'recreation' ? 'Étude de Maître' : 'Poésie Botanique'}
      VESSEL: ${params.pastryFormat || 'Single-tier Cake'}
      AURA: ${params.theme || 'Artistic Devotion'}
      INPUT POEM/SUBJECT: "${params.prompt}"

      YOU ARE FORBIDDEN FROM RETURNING ONLY TEXT. 
      YOU ARE FORBIDDEN FROM RETURNING ONLY AN IMAGE.
      YOU MUST RETURN BOTH: 
      1. THE PHOTOGRAPHIC IMAGE OF THE FINISHED CAKE.
      2. THE COMPLETE JSON DATA BLOCK INCLUDING TITLE, DESCRIPTION, TECHNIQUE, AND PEOTRACO MIXING RATIOS.
    ` 
  }];

  if (params.imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: params.imageData.split(',')[1]
      }
    });
  }

  try {
    // We use gemini-3-pro-image-preview for highest quality and adherence to complex logic
    return await callModel(ai, 'gemini-3-pro-image-preview', contents, params.mode);
  } catch (error: any) {
    console.error("Primary manifestation failed:", error);
    // Fallback to flash-image if pro fails, but keep the strict requirements
    const fallbackAi = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return await callModel(fallbackAi, 'gemini-2.5-flash-image', contents, params.mode);
  }
};

async function callModel(ai: any, modelName: string, contents: any[], mode: StudioMode): Promise<CakeDesign> {
  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: contents },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      // Increase thinking budget for complex color mixing logic
      thinkingConfig: { thinkingBudget: 4000 },
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: "1K"
      },
    },
  });

  let cakeData: any = null;
  let imageUrl: string | undefined;

  // 1. Extract Image
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }

  // 2. Extract JSON Data
  const fullText = response.text || "";
  try {
    // Regex to find the JSON block even if model wraps it in markdown
    const jsonMatch = fullText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      let cleanedJson = jsonMatch[0]
        .replace(/```json/g, '')
        .replace(/```/g, '')
        .trim();
      cakeData = JSON.parse(cleanedJson);
    }
  } catch (e) {
    console.error("Critical: Model returned malformed JSON or no JSON block.", e);
  }

  // VALIDATION: If we are missing critical data, we throw to trigger retry or show specific error
  if (!cakeData || !cakeData.colorRecipes || cakeData.colorRecipes.length === 0) {
    throw new Error("MANIFEST_DATA_INCOMPLETE: The model failed to provide technical mixing directives.");
  }

  return {
    id: Math.random().toString(36).substring(2, 9),
    timestamp: Date.now(),
    title: cakeData.title || "Manifestation Sans Titre",
    visualDescription: cakeData.visualDescription || "A vision that touched the creative ether.",
    technique: cakeData.technique || "Detailed gestural instructions were not captured properly.",
    colorRecipes: cakeData.colorRecipes,
    imageUrl: imageUrl,
    mode: mode,
    pastryFormat: cakeData.pastryFormat,
    theme: cakeData.theme
  };
}

