import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { CakeDesign, StudioMode } from "../types";

export interface GenerateParams {
  prompt: string;
  imageData?: string;
  pastryFormat?: string;
  theme?: string;
  mode: StudioMode;
}

export const generateCakeDesign = async (params: GenerateParams): Promise<CakeDesign> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Refined prompt to be extremely explicit about the dual requirement
  const promptText = `
    ATELIER DIRECTIVE: Manifest the following poem/subject into a luxury pastry.

    VESSEL: ${params.pastryFormat || 'Single-tier Cake'}
    AURA: ${params.theme || 'Artistic Devotion'}
    INPUT: "${params.prompt}"
    MODE: ${params.mode === 'recreation' ? 'Étude de Maître' : 'Poésie Botanique'}

    STRICT REQUIREMENT: 
    1. First, provide a TEXT output containing the JSON data block (title, visualDescription, technique, colorRecipes).
    2. Second, provide a visual IMAGE manifestation of the finished design.

    The colorRecipes MUST include specific Peotraco mixing parts (e.g., '3 parts White + 1 part Blue').
  `;

  const contents: any[] = [{ text: promptText }];

  if (params.imageData) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: params.imageData.split(',')[1]
      }
    });
  }

  try {
