async function callModel(ai: any, modelName: string, contents: any[], mode: StudioMode): Promise<CakeDesign> {
  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: contents },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      // Removed thinkingConfig as it can cause 400 errors with image generation models
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: "1K"
      },
    },
  });

  let cakeData: any = null;
  let imageUrl: string | undefined;

  // 1. Extract Image
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }

  // 2. Extract JSON Data
  const fullText = response.text || "";
  try {
    const jsonMatch = fullText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const cleanedJson = jsonMatch[0]
        .replace(/```json/g, '')
        .replace(/```/g, '')
        .trim();
      cakeData = JSON.parse(cleanedJson);
    }
  } catch (e) {
    console.error("Failed to parse manifest data from text:", fullText);
  }

  // Validation: Ensure we have the minimum required data to be "useful"
  if (!cakeData || !cakeData.colorRecipes || cakeData.colorRecipes.length === 0) {
    throw new Error("MANIFEST_DATA_INCOMPLETE: The model provided a vision but failed to transmit technical directives.");
  }

  return {
    id: Math.random().toString(36).substring(2, 9),
    timestamp: Date.now(),
    title: cakeData.title || "Manifestation Sans Titre",
    visualDescription: cakeData.visualDescription || "A vision of botanical soul.",
    technique: cakeData.technique || "Detailed gestural instructions were not captured.",
    colorRecipes: cakeData.colorRecipes,
    imageUrl: imageUrl,
    mode: mode,
    pastryFormat: cakeData.pastryFormat || "Patisserie",
    theme: cakeData.theme || "Artistic"
  };
}

