    CURRENT TASK: Manifest this vision.
    VESSEL: ${params.pastryFormat || 'Single-tier Cake'}
    THEME: ${params.theme || 'Artistic Devotion'}
    INPUT POEM/SUBJECT: "${params.prompt}"
    STUDIO MODE: ${studioModeName}

